const USERNAME = 'rttapi_bluegruntfuttock@gmail.com';
const PASSWORD = '7c5b8634ff592fe4969a2ae5f4f00303b1c7cc04';

const getAuthHeader = () => {
  try {
    return 'Basic ' + btoa(`${USERNAME}:${PASSWORD}`);
  } catch (e) {
    // Fallback for non-standard environments
    return 'Basic ' + Buffer.from(`${USERNAME}:${PASSWORD}`).toString('base64');
  }
};

/**
 * Fetches departures from Realtime Trains API.
 * NOTE: The RTT API (api.rtt.io) does not support CORS (Cross-Origin Resource Sharing)
 * from browser environments by default. In a production app, this call should be
 * routed through a backend proxy.
 */
export async function fetchDepartures(crs: string): Promise<RTTResponse> {
  const url = `https://api.rtt.io/api/v1/json/search/${crs}`;

  try {
    const response = await fetch(url, {
      method: 'GET',
      headers: {
        'Authorization': getAuthHeader(),
        'Accept': 'application/json'
      }
    });

    if (!response.ok) {
      if (response.status === 401 || response.status === 403) {
        throw new Error("Authentication failed. Please check RTT API credentials.");
      }
      throw new Error(`Station not found or API error (Status: ${response.status})`);
    }

    const data: RTTResponse = await response.json();

    if (data.error) {
      throw new Error(data.error);
    }

    return data;
  } catch (error: any) {
    console.error('Fetch Departures Failed:', error);
    // Specifically handle the common 'Failed to fetch' which indicates CORS issues
    if (error.message === 'Failed to fetch') {
      throw new Error("CORS Blocked: The Realtime Trains API does not allow direct browser access. This request requires a proxy.");
    }
    throw error;
  }
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse, AdjacentStation } from './types';
import { fetchDepartures } from './services/rttService';
import { findStationCrs, getAdjacentStations } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [adjacentStations, setAdjacentStations] = useState<AdjacentStation[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);

  const latestQueryRef = useRef('');
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setSearchResults([]);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Debounced Predictive Search
  useEffect(() => {
    latestQueryRef.current = searchQuery;

    // Minimum 2 chars to start predicting
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      return;
    }

    // Skip prediction if it exactly matches currently selected station (prevents loop)
    if (selectedStation && searchQuery.toLowerCase() === selectedStation.name.toLowerCase()) {
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
        }
      } catch (err) {
        console.error("Prediction error:", err);
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 350);

    return () => clearTimeout(timer);
  }, [searchQuery, selectedStation]);

  const loadStationData = useCallback(async (station: Station) => {
    setLoading(true);
    setError(null);
    setSelectedStation(station);
    setSearchQuery(station.name);
    setDepartures([]);
    setAdjacentStations([]);
    setSearchResults([]); 

    try {
      const data = await fetchDepartures(station.crs);
      setDepartures(data.services || []);
      setLastUpdated(new Date());

      // Concurrent fetch for adjacent stations to improve feel
      getAdjacentStations(station.name, station.crs)
        .then(setAdjacentStations)
        .catch(e => console.error("Adjacent station error:", e));

    } catch (err: any) {
      console.error(err);
      setError(err.message || "An unexpected error occurred while fetching departures.");
    } finally {
      setLoading(false);
    }
  }, []);

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (searchResults.length > 0) {
      loadStationData(searchResults[0]);
    }
  };

  const calculateStatus = (service: Service) => {
    const planned = service.locationDetail.gbttBookedDeparture;
    const actual = service.locationDetail.realtimeDeparture;

    if (!planned || !actual) return { text: "No Data", color: "text-slate-400" };

    const pMinutes = parseInt(planned.slice(0, 2)) * 60 + parseInt(planned.slice(2));
    const aMinutes = parseInt(actual.slice(0, 2)) * 60 + parseInt(actual.slice(2));

    const diff = aMinutes - pMinutes;

    if (diff <= 0) return { text: "On Time", color: "text-emerald-400" };
    if (diff > 59) return { text: "Delayed", color: "text-rose-400" };
    return { text: `${diff} min late`, color: "text-orange-400" };
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2)}`;
  };

  return (
    <div className="min-h-screen text-slate-200 p-4 md:p-8 max-w-5xl mx-auto pb-24">
