          </div>

          {/* Adjacent Stations Navigation */}
          {adjacentStations.length > 0 && (
            <div className="space-y-4">
               <h3 className="text-[10px] font-black text-slate-600 uppercase tracking-[0.2em]">Nearby Connections</h3>
