    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  const getDestinationName = (service: Service) => {
    const extract = (obj: any): string | null => {
        if (!obj) return null;
        if (Array.isArray(obj)) {
            const last = obj[obj.length - 1];
            return extract(last);
        }
        return obj.description || obj.locationName || obj.publicName || obj.name || null;
    };

    // 1. Primary check: Root-level destination (Standard RTT Search)
    const primary = extract(service.destination);
    if (primary) return primary;

    // 2. Secondary check: Nested in locationDetail (Common in some response types)
    const secondary = extract(service.locationDetail?.destination);
    if (secondary) return secondary;

    // 3. Last ditch checks on any potential string fields
    const anySvc = service as any;
    if (anySvc.destinationName) return anySvc.destinationName;
    if (anySvc.locationName && anySvc.locationName !== selectedStation?.name) return anySvc.locationName;

