                departures.map((service, idx) => {
                  const status = calculateStatus(service);
                  const platform = service.locationDetail?.displayAs || "-";
                  const destinationName = getDestinationName(service);
                  const scheduledTime = service.locationDetail?.gbttBookedDeparture || service.locationDetail?.gbttBookedArrival;

                  return (
                    <div 
                      key={`${service.serviceUid}-${idx}`}
                      className="grid grid-cols-12 gap-4 px-6 md:px-8 py-6 items-center hover:bg-white/[0.02] transition-colors group"
                    >
                      <div className="col-span-3 md:col-span-2">
                        <div className="text-2xl font-black mono text-white leading-none">
                          {formatTime(scheduledTime)}
                        </div>
                      </div>

                      <div className="col-span-6 md:col-span-4">
                        <div className="text-lg font-bold text-slate-100 truncate group-hover:text-blue-400 transition-colors tracking-tight">
                          {destinationName}
                        </div>
                        <div className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">
                          {service.trainIdentity} • {service.atocName || "National Rail"}
                        </div>
                      </div>

                      <div className="hidden md:block col-span-1 text-center font-bold mono text-slate-400">
                           {platform}
                      </div>

                      <div className="col-span-3 md:col-span-2 text-center">
                        <div className={`text-[11px] font-black uppercase tracking-wider px-2 py-1.5 rounded-lg bg-black/30 border border-white/5 ${status.color}`}>
                          {status.text}
                        </div>
                        {status.text !== "On Time" && (service.locationDetail?.realtimeDeparture || service.locationDetail?.realtimeArrival) && (
                          <div className="text-[10px] font-bold text-slate-600 mt-1.5 mono">
                            Exp {formatTime(service.locationDetail.realtimeDeparture || service.locationDetail.realtimeArrival)}
                          </div>
                        )}
                      </div>

                      <div className="hidden md:block col-span-3 text-right">
                        <div className="text-[11px] font-bold text-slate-400">
                           UID: {service.serviceUid}
                        </div>
                        <div className="text-[10px] font-medium text-slate-600 truncate mt-1 uppercase">
                           {service.serviceType || "Train"}
                        </div>
                      </div>

                      <div className="md:hidden col-span-12 mt-2 pt-2 border-t border-slate-800/50 flex justify-between items-center text-[10px] font-bold text-slate-600 uppercase">
                         <span>Platform {platform}</span>
                         <span>{service.serviceUid}</span>
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        </main>
      )}

      <footer className="mt-20 pt-8 border-t border-slate-800 flex flex-col items-center gap-4 text-slate-600 text-[10px] font-bold uppercase tracking-[0.2em] text-center">
        <div className="flex flex-wrap justify-center items-center gap-x-6 gap-y-3">
          <p className="flex items-center gap-2">
            <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-pulse" />
            API: Realtime Trains
          </p>
          <p>Intelligence: Gemini 3 Flash</p>
        </div>
        <p className="opacity-40">UK Rail Departures Pro.</p>
      </footer>
    </div>
  );
};

