                      </div>

                      <div className="col-span-3 md:col-span-3 text-right">
                        <div className={`inline-block text-[11px] font-black uppercase tracking-wider px-2 py-1.5 rounded-lg bg-black/30 border border-white/5 ${status.color}`}>
                          {status.text}
