            <div className="hidden md:grid grid-cols-12 gap-4 px-8 py-5 bg-slate-800/40 border-b border-slate-800 text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">
              <div className="col-span-2">Scheduled</div>
              <div className="col-span-7">Destination & Intermediate Stops</div>
              <div className="col-span-3 text-right">Status</div>
            </div>

            <div className="divide-y divide-slate-800/50">
              {loading ? (
                <div className="p-20 text-center flex flex-col items-center gap-6">
                  <div className="h-12 w-12 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin" />
                  <div className="text-slate-400 font-bold text-sm tracking-widest uppercase">Fetching Board...</div>
                </div>
              ) : error ? (
                <div className="p-16 text-center space-y-6">
                  <div className="inline-flex p-4 bg-rose-500/10 rounded-full text-rose-500">
                    <Icons.Refresh />
                  </div>
                  <div className="space-y-2">
                    <h3 className="text-white font-bold text-lg">Unable to load services</h3>
                    <p className="text-slate-500 text-sm max-w-sm mx-auto leading-relaxed">{error}</p>
                  </div>
                  <button 
                    onClick={() => loadStationData(selectedStation)}
                    className="px-6 py-2 bg-slate-800 border border-slate-700 rounded-xl text-white text-sm font-bold hover:bg-slate-700 transition-all"
                  >
                    Try Again
                  </button>
                </div>
              ) : departures.length === 0 ? (
                <div className="p-20 text-center space-y-2">
                  <div className="text-slate-400 font-bold text-lg">No services scheduled</div>
                  <div className="text-slate-600 text-sm">There are no departures in the current window.</div>
                </div>
              ) : (
                departures.map((service, idx) => {
                  const status = calculateStatus(service);
                  const destinationName = getFullDestinationName(service);
                  const scheduledTime = service.locationDetail?.gbttBookedDeparture || service.locationDetail?.gbttBookedArrival;

                  return (
                    <div 
                      key={`${service.serviceUid}-${idx}`}
                      className="grid grid-cols-12 gap-4 px-6 md:px-8 py-6 items-center hover:bg-white/[0.02] transition-colors group"
                    >
                      <div className="col-span-3 md:col-span-2">
                        <div className="text-2xl font-black mono text-white leading-none">
                          {formatTime(scheduledTime)}
                        </div>
                      </div>

                      <div className="col-span-6 md:col-span-7 overflow-hidden">
                        <div className="text-lg font-bold text-slate-100 truncate group-hover:text-blue-400 transition-colors tracking-tight">
                          {destinationName}
                        </div>

                        <div className="mt-2 flex items-center gap-2 overflow-x-auto no-scrollbar scroll-smooth">
                           <span className="text-[9px] font-black text-slate-600 uppercase whitespace-nowrap">Calling At:</span>
                           {service.callingPoints ? (
                             <div className="flex items-center gap-1.5 pb-1">
                               {service.callingPoints.map((stop, sIdx) => (
                                 <React.Fragment key={sIdx}>
                                   <span className="text-[10px] font-medium text-slate-400 bg-slate-800/50 px-2 py-0.5 rounded whitespace-nowrap border border-white/5">
                                     {stop}
                                   </span>
                                   {sIdx < service.callingPoints!.length - 1 && (
                                     <span className="text-slate-700 text-[8px]">•</span>
                                   )}
                                 </React.Fragment>
                               ))}
                             </div>
                           ) : enriching ? (
                             <div className="flex gap-2 items-center">
                               <div className="h-3.5 w-16 bg-blue-500/10 animate-pulse rounded" />
                               <div className="h-3.5 w-24 bg-blue-500/10 animate-pulse rounded" />
                               <span className="text-[8px] text-blue-500/40 animate-pulse font-black uppercase ml-1">Identifying route...</span>
                             </div>
                           ) : (
                             <span className="text-[10px] text-slate-700 font-medium">Non-stop to {destinationName}</span>
                           )}
                        </div>
                      </div>

                      <div className="col-span-3 md:col-span-3 text-right">
                        <div className={`inline-block text-[11px] font-black uppercase tracking-wider px-2 py-1.5 rounded-lg bg-black/30 border border-white/5 ${status.color}`}>
                          {status.text}
                        </div>
                        {status.text !== "On Time" && (service.locationDetail?.realtimeDeparture || service.locationDetail?.realtimeArrival) && (
                          <div className="text-[10px] font-bold text-slate-600 mt-1.5 mono">
                            Exp {formatTime(service.locationDetail.realtimeDeparture || service.locationDetail.realtimeArrival)}
                          </div>
                        )}
                        <div className="text-[9px] text-slate-700 font-bold uppercase mt-1 tracking-widest hidden md:block">
                          {service.atocName || "National Rail"}
                        </div>
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        </main>
      )}

      <footer className="mt-20 pt-8 border-t border-slate-800 flex flex-col items-center gap-4 text-slate-600 text-[10px] font-bold uppercase tracking-[0.2em] text-center">
        <div className="flex flex-wrap justify-center items-center gap-x-6 gap-y-3">
          <p className="flex items-center gap-2">
            <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-pulse" />
            API: Realtime Trains
          </p>
          <p>Intelligence: Gemini 3 Flash</p>
        </div>
        <p className="opacity-40">UK Rail Departures Pro.</p>
      </footer>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </div>
  );
};

export default App;

export interface Station {
  name: string;
  crs: string;
}

export interface LocationDetail {
  realtimeActivated: boolean;
  crs: string;
  description: string;
  gbttBookedArrival?: string;
  gbttBookedDeparture?: string;
  realtimeArrival?: string;
  realtimeDeparture?: string;
  realtimeArrivalActual?: boolean;
  realtimeDepartureActual?: boolean;
  displayAs?: string;
  // Fallback destination often found here in some RTT versions
  destination?: any;
  origin?: any;
}

export interface Service {
  locationDetail: LocationDetail;
  serviceUid: string;
  runDate: string;
  trainIdentity: string;
  runningIdentity?: string;
  atocCode?: string;
  atocName?: string;
  serviceType?: string;
  isPassenger?: boolean;
  origin?: any;
  destination?: any;
  // Enriched field for UI
  callingPoints?: string[];
}

export interface RTTResponse {
  location?: {
    name: string;
    crs: string;
  };
  services?: Service[] | null;
  error?: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Station } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function findStationCrs(query: string): Promise<Station[]> {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Find the 3-letter CRS codes for UK railway stations matching or similar to: "${query}". Return the most likely candidates.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            crs: { type: Type.STRING }
          },
          required: ["name", "crs"]
        }
      }
    }
  });

  try {
    return JSON.parse(response.text || "[]");
  } catch {
    return [];
  }
}

export interface RouteStops {
  destination: string;
  stops: string[];
}

export async function getRouteCallingPoints(routes: {origin: string, via: string, destination: string}[]): Promise<RouteStops[]> {
  if (routes.length === 0) return [];

  const viaStation = routes[0].via;
  const routeList = routes.map(r => `- To ${r.destination}`).join('\n');

  const prompt = `For a train currently at "${viaStation}", list 3-5 major intermediate calling points (stations) it will stop at BEFORE reaching the following destinations.
Destinations:
${routeList}

Instructions:
1. ONLY include stops between "${viaStation}" and the Destination.
2. Return a list of objects containing the "destination" and the array of "stops".
3. If it is a non-stop service, return an empty array for stops.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            destination: { type: Type.STRING },
            stops: { 
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["destination", "stops"]
        }
      }
    }
  });

  try {
    return JSON.parse(response.text || "[]");
  } catch (err) {
    console.error("Calling points parse error:", err);
    return [];
  }
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse } from './types';
import { fetchDepartures } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);

  const latestQueryRef = useRef('');
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setSearchResults([]);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      return;
    }
    if (selectedStation && searchQuery.toLowerCase() === selectedStation.name.toLowerCase()) {
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
        }
      } catch (err) {
        console.error("Prediction error:", err);
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery, selectedStation]);

  const getStationName = (obj: any): string => {
    if (!obj) return "";
    if (Array.isArray(obj)) {
      if (obj.length === 0) return "";
      return getStationName(obj[obj.length - 1]);
    }
    return obj.description || obj.locationName || obj.publicName || obj.name || obj.crs || "";
  };

  const getFullDestinationName = (service: Service): string => {
    let name = getStationName(service.destination);
    if (!name && service.locationDetail) {
      name = getStationName(service.locationDetail.destination);
    }
    return name || "Check Board";
  };

  const loadStationData = useCallback(async (station: Station) => {
    if (!station || !station.crs) return;

    setLoading(true);
    setEnriching(false);
    setError(null);
    setSelectedStation(station);
    setSearchQuery(station.name);
    setDepartures([]);
    setSearchResults([]); 

    try {
      const data = await fetchDepartures(station.crs);
      const services = Array.isArray(data.services) ? data.services : [];

      setDepartures(services);
      setLastUpdated(new Date());

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 10).map(s => ({
          origin: getStationName(s.origin) || "Origin",
          destination: getFullDestinationName(s),
          via: station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults || enrichedResults.length === 0) return;

          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || 
              destName.includes(r.destination.toLowerCase())
            );

            if (match && match.stops.length > 0) {
              return { ...s, callingPoints: match.stops };
            }
            return s;
          }));
        }).catch(err => {
          console.warn("Failed to fetch calling points:", err);
        }).finally(() => {
          setEnriching(false);
        });
      }

    } catch (err: any) {
      console.error(err);
      setError(err.message || "An unexpected error occurred.");
    } finally {
      setLoading(false);
    }
  }, []);

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (searchResults.length > 0) {
      loadStationData(searchResults[0]);
    }
  };

  const calculateStatus = (service: Service) => {
    if (!service || !service.locationDetail) return { text: "No Data", color: "text-slate-500" };

    const planned = service.locationDetail.gbttBookedDeparture || service.locationDetail.gbttBookedArrival;
    const actual = service.locationDetail.realtimeDeparture || service.locationDetail.realtimeArrival;

    if (!planned) return { text: "Scheduled", color: "text-blue-400" };
    if (!actual || actual === planned) return { text: "On Time", color: "text-emerald-400" }; 

    try {
      const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
      const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);

      let diff = aMin - pMin;
      if (diff < -1200) diff += 1440;
      if (diff > 1200) diff -= 1440;

      if (diff <= 0) return { text: "On Time", color: "text-emerald-400" };
      if (diff > 59) return { text: "Delayed", color: "text-rose-400" };
      return { text: `${diff} min late`, color: "text-orange-400" };
    } catch (e) {
      return { text: "Live", color: "text-blue-400" };
    }
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr || timeStr.length < 4) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  return (
    <div className="min-h-screen text-slate-200 p-4 sm:p-6 md:p-10 max-w-6xl mx-auto pb-24">
      <header className="mb-8 md:mb-12 text-center">
        <div className="flex items-center justify-center gap-3 mb-2">
          <div className="p-2 md:p-2.5 bg-blue-600 rounded-xl text-white shadow-lg shadow-blue-500/20">
            <Icons.Train />
          </div>
          <h1 className="text-2xl md:text-4xl font-extrabold tracking-tight text-white">UK Rail Live</h1>
        </div>
        <p className="text-slate-400 text-xs md:text-sm font-medium uppercase tracking-[0.1em]">Real-time Departure Intelligence</p>
      </header>

      <section className="relative z-50 bg-slate-800/40 backdrop-blur-md border border-slate-700/50 rounded-2xl md:rounded-3xl p-5 md:p-8 shadow-2xl mb-8 md:mb-12 transition-all">
        <form onSubmit={handleSearchSubmit} className="flex flex-col sm:flex-row gap-3">
          <div className="relative flex-1">
            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-slate-500">
              {isSearching ? (
                <div className="animate-spin h-4 w-4 border-2 border-blue-500 border-t-transparent rounded-full ml-1" />
              ) : (
                <Icons.Search />
              )}
            </div>
            <input
              type="text"
              className="block w-full pl-12 pr-4 py-4 bg-slate-900 border border-slate-700 rounded-2xl text-white placeholder-slate-500 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none text-lg"
              placeholder="Search station..."
              value={searchQuery}
              autoComplete="off"
              onChange={(e) => setSearchQuery(e.target.value)}
              onFocus={() => { if(selectedStation) setSearchQuery('') }}
            />
          </div>
          <button
            type="submit"
            className="px-8 py-4 bg-blue-600 hover:bg-blue-500 text-white font-bold rounded-2xl transition-all shadow-lg shadow-blue-900/40 active:scale-95 text-lg"
          >
            Search
          </button>
        </form>

        {searchResults.length > 0 && (
          <div ref={dropdownRef} className="absolute left-5 right-5 top-full mt-3 bg-slate-800 border border-slate-700 rounded-2xl shadow-2xl overflow-hidden z-50 ring-1 ring-white/10">
            <div className="max-h-72 overflow-y-auto divide-y divide-slate-700/50">
              {searchResults.map((s) => (
                <button
                  key={s.crs}
                  onClick={() => loadStationData(s)}
                  className="w-full flex items-center justify-between p-5 hover:bg-slate-700/80 text-left transition-colors group"
                >
                  <div>
                    <div className="font-bold text-white group-hover:text-blue-400 transition-colors text-lg">{s.name}</div>
                    <div className="text-[10px] text-slate-500 uppercase font-black tracking-[0.2em] mt-1">{s.crs}</div>
                  </div>
                  <div className="text-slate-600 group-hover:text-blue-500 group-hover:translate-x-1 transition-all">
                    <Icons.ChevronRight />
                  </div>
                </button>
              ))}
            </div>
          </div>
        )}

        {!selectedStation && searchResults.length === 0 && !searchQuery && (
          <div className="mt-10">
            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] mb-6 flex items-center gap-3">
              <span className="h-px bg-slate-700 flex-1"></span>
              <span className="flex items-center gap-2"><Icons.MapPin /> Major Hubs</span>
              <span className="h-px bg-slate-700 flex-1"></span>
            </h3>
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-5 gap-3">
              {MAJOR_STATIONS.map((s) => (
                <button
                  key={s.crs}
                  onClick={() => loadStationData(s)}
                  className="px-4 py-3 bg-slate-900/50 border border-slate-700 hover:border-blue-500/50 hover:bg-slate-800 text-slate-300 hover:text-white rounded-xl text-xs font-bold transition-all truncate"
                >
                  {s.name}
                </button>
              ))}
            </div>
          </div>
        )}
      </section>

      {selectedStation && (
        <main className="space-y-6 md:space-y-10 animate-in fade-in zoom-in-95 duration-500">
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 pb-6 md:pb-10 border-b border-slate-800/50">
            <div className="space-y-2">
              <div className="inline-flex items-center gap-2 px-3 py-1 bg-blue-500/10 border border-blue-500/30 rounded-lg text-blue-500 font-black tracking-[0.3em] text-[10px] uppercase">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-blue-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-blue-500"></span>
                </span>
                {selectedStation.crs}
              </div>
              <h2 className="text-4xl md:text-6xl font-black text-white tracking-tight leading-none">{selectedStation.name}</h2>
              {lastUpdated && (
                <div className="text-xs text-slate-500 font-bold uppercase tracking-widest flex items-center gap-2">
                  <Icons.Refresh /> Updated {lastUpdated.toLocaleTimeString()}
                </div>
              )}
            </div>

            <div className="flex items-center gap-3 w-full md:w-auto">
               <button 
                onClick={() => loadStationData(selectedStation)}
                disabled={loading}
                className="flex-1 md:flex-none flex items-center justify-center gap-2 px-6 py-3 bg-slate-800 border border-slate-700 rounded-2xl hover:bg-slate-700 transition-all text-slate-300 hover:text-white disabled:opacity-50"
               >
                 <div className={loading ? "animate-spin" : ""}>
                    <Icons.Refresh />
                 </div>
                 <span className="text-sm font-black uppercase tracking-widest">Refresh</span>
               </button>
               <button 
                onClick={() => {
                  setSelectedStation(null);
                  setSearchQuery('');
                  setDepartures([]);
                }}
                className="px-6 py-3 text-sm font-black uppercase tracking-widest text-slate-500 hover:text-white transition-colors"
               >
                 Change
               </button>
            </div>
          </div>

          <div className="bg-slate-900/80 border border-slate-800 rounded-[2rem] overflow-hidden shadow-2xl ring-1 ring-white/5 backdrop-blur-sm">
            <div className="hidden lg:grid grid-cols-12 gap-4 px-10 py-6 bg-slate-800/30 border-b border-slate-800 text-[10px] font-black uppercase tracking-[0.3em] text-slate-500">
              <div className="col-span-2">Scheduled</div>
              <div className="col-span-7">Destination & Route</div>
              <div className="col-span-3 text-right">Service Status</div>
            </div>

            <div className="divide-y divide-slate-800/40">
              {loading ? (
                <div className="p-32 text-center flex flex-col items-center gap-8">
                  <div className="h-16 w-16 border-[5px] border-blue-500/20 border-t-blue-500 rounded-full animate-spin" />
                  <div className="text-slate-400 font-black text-xs tracking-[0.4em] uppercase">Initializing Board</div>
                </div>
              ) : error ? (
                <div className="p-20 text-center space-y-8">
                  <div className="inline-flex p-6 bg-rose-500/10 rounded-3xl text-rose-500">
                    <Icons.Refresh />
                  </div>
                  <div className="space-y-3">
                    <h3 className="text-white font-black text-2xl">Network Interrupted</h3>
                    <p className="text-slate-500 text-sm max-w-sm mx-auto leading-relaxed">{error}</p>
                  </div>
                  <button 
                    onClick={() => loadStationData(selectedStation)}
                    className="px-10 py-4 bg-slate-800 border border-slate-700 rounded-2xl text-white text-sm font-black uppercase tracking-widest hover:bg-slate-700 transition-all"
                  >
                    Reconnect
                  </button>
                </div>
              ) : departures.length === 0 ? (
                <div className="p-32 text-center space-y-4">
                  <div className="text-slate-400 font-black text-2xl uppercase tracking-tighter italic opacity-20">No Services</div>
                  <div className="text-slate-600 text-xs font-bold uppercase tracking-widest">The board is currently clear.</div>
                </div>
              ) : (
                departures.map((service, idx) => {
                  const status = calculateStatus(service);
                  const destinationName = getFullDestinationName(service);
                  const scheduledTime = service.locationDetail?.gbttBookedDeparture || service.locationDetail?.gbttBookedArrival;

                  return (
                    <div 
                      key={`${service.serviceUid}-${idx}`}
                      className="grid grid-cols-12 gap-3 md:gap-4 px-6 md:px-10 py-8 items-center hover:bg-white/[0.03] transition-colors group cursor-default"
                    >
                      <div className="col-span-3 lg:col-span-2">
                        <div className="text-2xl md:text-3xl font-black mono text-white leading-none tracking-tighter">
                          {formatTime(scheduledTime)}
                        </div>
                      </div>

                      <div className="col-span-6 lg:col-span-7 overflow-hidden">
                        <div className="text-lg md:text-2xl font-black text-slate-100 truncate group-hover:text-blue-400 transition-colors tracking-tight">
                          {destinationName}
                        </div>

                        <div className="mt-3 flex items-center gap-2 overflow-x-auto no-scrollbar scroll-smooth">
                           <span className="text-[8px] md:text-[9px] font-black text-slate-600 uppercase whitespace-nowrap bg-black/20 px-1.5 py-0.5 rounded">Calls:</span>
                           {service.callingPoints ? (
                             <div className="flex items-center gap-1.5 pb-1">
                               {service.callingPoints.map((stop, sIdx) => (
                                 <React.Fragment key={sIdx}>
                                   <span className="text-[10px] md:text-[11px] font-bold text-slate-400 bg-slate-800 border border-white/5 px-2.5 py-1 rounded-lg whitespace-nowrap shadow-sm">
                                     {stop}
                                   </span>
                                   {sIdx < service.callingPoints!.length - 1 && (
                                     <Icons.ChevronRight />
                                   )}
                                 </React.Fragment>
                               ))}
                             </div>
                           ) : enriching ? (
                             <div className="flex gap-2 items-center">
                               <div className="h-4 w-16 bg-blue-500/10 animate-pulse rounded-md" />
                               <div className="h-4 w-24 bg-blue-500/10 animate-pulse rounded-md" />
                             </div>
                           ) : (
                             <span className="text-[10px] text-slate-700 font-black uppercase tracking-widest italic opacity-60">Express Service</span>
                           )}
                        </div>
                      </div>

                      <div className="col-span-3 lg:col-span-3 text-right">
                        <div className={`inline-block text-[10px] md:text-[12px] font-black uppercase tracking-widest px-3 py-2 rounded-xl bg-black/40 border border-white/5 ${status.color}`}>
                          {status.text}
                        </div>
                        {status.text !== "On Time" && (service.locationDetail?.realtimeDeparture || service.locationDetail?.realtimeArrival) && (
                          <div className="text-[10px] font-black text-slate-600 mt-2 mono tracking-tight">
                            EXP {formatTime(service.locationDetail.realtimeDeparture || service.locationDetail.realtimeArrival)}
                          </div>
                        )}
                        <div className="text-[8px] text-slate-700 font-black uppercase mt-2 tracking-[0.2em] hidden sm:block">
                          {service.atocName || "National Rail"}
                        </div>
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        </main>
      )}

      <footer className="mt-20 pt-10 border-t border-slate-800/50 flex flex-col md:flex-row justify-between items-center gap-6 text-slate-600 text-[10px] font-black uppercase tracking-[0.3em] text-center md:text-left">
        <div className="flex flex-col md:flex-row items-center gap-x-10 gap-y-4">
          <p className="flex items-center gap-3">
            <span className="w-2 h-2 bg-blue-500 rounded-full shadow-[0_0_8px_rgba(59,130,246,0.6)]" />
            Live Data Feed
          </p>
          <p className="flex items-center gap-2">Gemini 3 Pro Route Engine</p>
        </div>
        <p className="opacity-30">© {new Date().getFullYear()} Rail Departures Pro</p>
      </footer>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }

        @media (max-width: 640px) {
          .grid-cols-12 { gap: 0.5rem; }
          .px-6 { padding-left: 1.25rem; padding-right: 1.25rem; }
        }

        /* Portrait optimizations */
        @media (orientation: portrait) {
          h2 { font-size: 2.75rem; line-height: 1; }
          .py-8 { padding-top: 1.5rem; padding-bottom: 1.5rem; }
