             title="Refresh"
           >
             <div className={loading ? "animate-spin" : ""}>
                <Icons.Refresh />
             </div>
           </button>
           <button 
             onClick={resetToSearch}
             className="flex items-center gap-2 px-3 py-1.5 md:px-5 md:py-2 bg-white text-black hover:bg-slate-200 rounded-full font-black text-[9px] md:text-xs uppercase tracking-widest transition-all shadow-lg active:scale-95"
           >
             <Icons.Search />
             <span className="hidden sm:inline">Search</span>
           </button>
        </div>
      </nav>

      {/* Main Board Content - Compact padding */}
      <main className="pt-16 md:pt-20 pb-8 px-1 sm:px-2 md:px-6 max-w-[1500px] mx-auto animate-in fade-in zoom-in-95 duration-500">
        <div className="rounded-2xl md:rounded-3xl bg-[#0c0c0c] border border-white/5 shadow-2xl overflow-hidden">
          {/* Board Headers - Landscape Only - Compact */}
          <div className="hidden md:grid grid-cols-12 gap-4 px-8 py-3 bg-zinc-900/50 border-b border-white/5 text-[8px] font-black uppercase tracking-[0.4em] text-zinc-500">
            <div className="col-span-2">Scheduled</div>
            <div className="col-span-7">Destination & Intermediate Stops</div>
            <div className="col-span-3 text-right">Status</div>
          </div>

          <div className="divide-y divide-white/5">
            {loading ? (
              <div className="p-32 text-center flex flex-col items-center gap-6">
                <div className="relative">
                  <div className="h-16 w-16 border-[4px] border-blue-500/10 border-t-blue-500 rounded-full animate-spin" />
                </div>
                <div className="text-slate-500 font-black text-[9px] tracking-[0.4em] uppercase animate-pulse">Scanning Platform...</div>
              </div>
