                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                );
              })
            )}
          </div>
        </div>
      </main>

      {/* Minimal Footer */}
      <footer className="px-6 py-6 flex flex-col md:flex-row justify-between items-center gap-4 border-t border-white/5 opacity-40">
         <div className="flex items-center gap-6 text-[8px] font-black uppercase tracking-[0.2em] text-zinc-600">
            <span className="flex items-center gap-1.5"><span className="w-1.5 h-1.5 rounded-full bg-blue-600" /> LIVE DATA</span>
            <span>GEMINI ENGINE</span>
         </div>
         <div className="text-[8px] font-black uppercase tracking-[0.2em] text-zinc-800">
           UPDATED {lastUpdated?.toLocaleTimeString()}
         </div>
      </footer>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }

        @media (orientation: landscape) and (max-height: 600px) {
           nav { padding-top: 0.5rem; padding-bottom: 0.5rem; }
           .pt-16 { padding-top: 3.5rem; }
           .py-4 { padding-top: 0.75rem; padding-bottom: 0.75rem; }
           .text-2xl { font-size: 1.25rem; }
           .text-lg { font-size: 1rem; }
        }

        /* Ensure at least 4 items visible by default on standard screens */
        @media (min-height: 800px) {
           .py-5 { padding-top: 1.5rem; padding-bottom: 1.5rem; }
        }
      `}</style>
    </div>
  );
};

