    console.error('RTT Fetch Error:', error);
    if (error.name === 'TypeError') {
      throw new Error("Network error: The API proxy might be down.");
    }
    throw error;
  }
}

import { GoogleGenAI, Type } from "@google/genai";
import { Station } from "../types";

export async function findStationCrs(query: string): Promise<Station[]> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Find the 3-letter CRS codes for UK railway stations matching or similar to: "${query}". Return the most likely candidates.`,
      config: {
        responseMimeType: "application/json",
        thinkingConfig: { thinkingBudget: 0 },
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              crs: { type: Type.STRING }
            },
            required: ["name", "crs"]
          }
        }
      }
    });

    const text = response.text;
    if (!text) return [];
    return JSON.parse(text);
  } catch (err) {
    console.error("Station search error:", err);
    throw new Error("Station lookup service currently unavailable.");
  }
}

export interface RouteStops {
  destination: string;
  stops: string[];
}

export async function getRouteCallingPoints(routes: {origin: string, via: string, destination: string}[]): Promise<RouteStops[]> {
  if (routes.length === 0) return [];

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const viaStation = routes[0].via;
  const routeList = routes.map(r => `- To ${r.destination}`).join('\n');

  const prompt = `For a train currently at "${viaStation}", list 3-5 major intermediate calling points (stations) it will stop at BEFORE reaching the following destinations.
Destinations:
${routeList}

Instructions:
1. ONLY include stops between "${viaStation}" and the Destination.
2. Return a list of objects containing the "destination" and the array of "stops".
3. If it is a non-stop service, return an empty array for stops.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        thinkingConfig: { thinkingBudget: 0 },
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              destination: { type: Type.STRING },
              stops: { 
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            },
            required: ["destination", "stops"]
          }
        }
      }
    });

    const text = response.text;
    if (!text) return [];
    return JSON.parse(text);
  } catch (err) {
    console.error("Calling points enrichment error:", err);
    return [];
  }
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse } from './types';
import { fetchDepartures } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);

  const latestQueryRef = useRef('');

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      setSearchError(null);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      setSearchError(null);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
          if (!results || results.length === 0) {
             setSearchError("No stations found");
          }
        }
      } catch (err) {
        console.error("Search error:", err);
        if (latestQueryRef.current === searchQuery) {
          setSearchError("Lookup service unavailable");
        }
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const getStationName = (obj: any): string => {
    if (!obj) return "";
    if (Array.isArray(obj)) {
      if (obj.length === 0) return "";
      return getStationName(obj[obj.length - 1]);
    }
    return obj.description || obj.locationName || obj.publicName || obj.name || obj.crs || "";
  };

  const getFullDestinationName = (service: Service): string => {
    let name = getStationName(service.destination);
    if (!name && service.locationDetail) {
      name = getStationName(service.locationDetail.destination);
    }
    return name || "Check Board";
  };

  const loadStationData = useCallback(async (station: Station, silent: boolean = false) => {
    if (!station || !station.crs) return;

    if (!silent) {
      setLoading(true);
      setDepartures([]);
    }

    setEnriching(false);
    setError(null);
    setSelectedStation(station);
    setSearchQuery('');

    try {
      const data = await fetchDepartures(station.crs);
      const services = Array.isArray(data.services) ? data.services : [];

      setDepartures(services);
      setLastUpdated(new Date());

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 15).map(s => ({
          origin: getStationName(s.origin) || "Origin",
          destination: getFullDestinationName(s),
          via: station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults || enrichedResults.length === 0) return;

          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || 
              destName.includes(r.destination.toLowerCase())
            );

            if (match && match.stops.length > 0) {
              return { ...s, callingPoints: match.stops };
            }
            return s;
          }));
        }).catch(err => {
          console.warn("Failed to fetch calling points:", err);
        }).finally(() => {
          setEnriching(false);
        });
      }

    } catch (err: any) {
      console.error(err);
      if (!silent) {
        setError(err.message || "An unexpected error occurred.");
      }
    } finally {
      if (!silent) {
        setLoading(false);
      }
    }
  }, []);

  // Automatic Refresh Logic: Every 30 seconds
  useEffect(() => {
    if (!selectedStation) return;

    const interval = setInterval(() => {
      loadStationData(selectedStation, true);
    }, 30000);

    return () => clearInterval(interval);
  }, [selectedStation, loadStationData]);

  const calculateStatus = (service: Service) => {
    if (!service || !service.locationDetail) return { text: "No Data", color: "text-slate-500", bg: "bg-slate-500/10" };
    const planned = service.locationDetail.gbttBookedDeparture || service.locationDetail.gbttBookedArrival;
    const actual = service.locationDetail.realtimeDeparture || service.locationDetail.realtimeArrival;

    if (!planned) return { text: "Scheduled", color: "text-blue-400", bg: "bg-blue-400/10" };
    if (!actual || actual === planned) return { text: "On Time", color: "text-emerald-400", bg: "bg-emerald-400/10" }; 

    try {
      const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
      const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
      let diff = aMin - pMin;
      if (diff < -1200) diff += 1440;
      if (diff > 1200) diff -= 1440;

      if (diff <= 0) return { text: "On Time", color: "text-emerald-400", bg: "bg-emerald-400/10" };
      if (diff > 59) return { text: "Delayed", color: "text-rose-400", bg: "bg-rose-400/10" };
      return { text: `${diff}m Late`, color: "text-orange-400", bg: "bg-orange-400/10" };
    } catch (e) {
      return { text: "Live", color: "text-blue-400", bg: "bg-blue-400/10" };
    }
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr || timeStr.length < 4) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  const resetToSearch = () => {
    setSelectedStation(null);
    setDepartures([]);
    setSearchQuery('');
    setSearchError(null);
  };

  if (!selectedStation) {
    return (
      <div className="min-h-screen text-slate-200 flex flex-col items-center justify-start pt-6 md:pt-12 p-4 sm:p-6 transition-all bg-[#0b1120]">
        <div className="w-full max-w-xl animate-in fade-in slide-in-from-bottom-2 duration-700">
          <header className="mb-4 flex items-center justify-center gap-3">
            <div className="p-1.5 bg-blue-600 rounded-xl text-white shadow-lg">
              <Icons.Train />
            </div>
            <div className="text-left">
              <h1 className="text-xl md:text-2xl font-black tracking-tighter text-white italic uppercase leading-none">UK Rail Live</h1>
              <p className="text-slate-500 text-[8px] font-black uppercase tracking-[0.3em]">Real-time Departures</p>
            </div>
          </header>

          <div className="relative group">
            <div className="relative bg-slate-900 border border-slate-700 rounded-xl p-0.5 shadow-xl">
              <div className="relative flex items-center">
                <div className="absolute left-4 text-slate-500 scale-75">
                  {isSearching ? <div className="animate-spin h-4 w-4 border-2 border-blue-500 border-t-transparent rounded-full" /> : <Icons.Search />}
                </div>
                <input
                  type="text"
                  className="w-full pl-11 pr-4 py-2.5 bg-transparent text-white placeholder-slate-500 focus:outline-none text-base md:text-lg font-bold"
                  placeholder="Enter station name..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  autoFocus
                />
              </div>

              {searchError && (
                <div className="px-4 py-2 text-[10px] font-black text-rose-500 uppercase tracking-widest border-t border-slate-800 bg-rose-500/5">
                   {searchError}
                </div>
              )}

              {searchResults.length > 0 && (
                <div className="mt-0.5 border-t border-slate-800 max-h-64 overflow-y-auto no-scrollbar">
                  {searchResults.map((s) => (
                    <button
                      key={s.crs}
                      onClick={() => loadStationData(s)}
                      className="w-full flex items-center justify-between p-2.5 hover:bg-white/5 text-left transition-colors group"
                    >
                      <div className="flex items-baseline gap-2">
                        <div className="font-bold text-white group-hover:text-blue-400 text-sm md:text-base">{s.name}</div>
                        <div className="text-[9px] text-slate-600 uppercase font-black tracking-widest">{s.crs}</div>
                      </div>
                      <div className="text-slate-800 group-hover:text-blue-500 scale-75">
                        <Icons.ChevronRight />
                      </div>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>

          {!searchResults.length && !searchQuery && (
            <div className="mt-4">
              <div className="flex items-center gap-3 mb-3">
                <div className="h-px bg-slate-800 flex-1"></div>
                <h3 className="text-[8px] font-black text-slate-600 uppercase tracking-[0.4em]">Popular Hubs</h3>
                <div className="h-px bg-slate-800 flex-1"></div>
              </div>
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-1.5">
                {MAJOR_STATIONS.map((s) => (
                  <button
                    key={s.crs}
                    onClick={() => loadStationData(s)}
                    className="px-2 py-1.5 bg-slate-900/40 border border-slate-800/50 hover:border-blue-500/50 hover:bg-slate-800 text-slate-400 hover:text-white rounded-lg text-[9px] font-bold transition-all truncate"
                  >
                    {s.name}
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-slate-100 selection:bg-blue-500/30">
      <nav className="fixed top-0 left-0 right-0 z-50 bg-black/90 backdrop-blur-xl border-b border-white/10 px-4 md:px-8 py-2 md:py-3 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="flex flex-col">
             <div className="flex items-center gap-2">
                <span className="text-blue-500 font-black tracking-widest text-[9px] uppercase">{selectedStation.crs}</span>
