import { RTTResponse, Service, ServiceDetail } from "../types";

const USERNAME = 'rttapi_bluegruntfuttock@gmail.com';
const PASSWORD = '7c5b8634ff592fe4969a2ae5f4f00303b1c7cc04';

const getAuthHeader = () => {
  return 'Basic ' + btoa(`${USERNAME}:${PASSWORD}`);
};

/**
 * Normalizes HHMM strings into a comparable number, 
 * handling the midnight wrap-around relative to a reference time.
 */
function getSortTime(timeStr: string, refMinutes: number): number {
  const hours = parseInt(timeStr.slice(0, 2), 10);
  const mins = parseInt(timeStr.slice(2, 4), 10);
  let totalMins = hours * 60 + mins;

  if (totalMins < refMinutes - 120) {
    totalMins += 1440; 
  }

  return totalMins;
}

export async function fetchDepartures(crs: string): Promise<RTTResponse> {
  const targetUrl = `https://api.rtt.io/api/v1/json/search/${crs}`;
  const proxiedUrl = `https://corsproxy.io/?${encodeURIComponent(targetUrl)}`;

  try {
    const response = await fetch(proxiedUrl, {
      method: 'GET',
      headers: {
        'Authorization': getAuthHeader(),
        'Accept': 'application/json'
      }
    });

    if (!response.ok) {
      if (response.status === 401 || response.status === 403) {
        throw new Error("RTT Authentication failed.");
      }
      throw new Error(`Service Error (${response.status})`);
    }

    const data: RTTResponse = await response.json();

    if (data.error) {
      throw new Error(`RTT Error: ${data.error}`);
    }

    if (data.services && Array.isArray(data.services)) {
      const now = new Date();
      const currentMinutes = now.getHours() * 60 + now.getMinutes();

      data.services.sort((a, b) => {
        const timeA = a.locationDetail?.gbttBookedDeparture || a.locationDetail?.realtimeDeparture || "0000";
        const timeB = b.locationDetail?.gbttBookedDeparture || b.locationDetail?.realtimeDeparture || "0000";

        const sortA = getSortTime(timeA, currentMinutes);
        const sortB = getSortTime(timeB, currentMinutes);

        return sortA - sortB;
      });
    } else {
      data.services = [];
    }

    return data;
  } catch (error: any) {
    console.error('RTT Fetch Error:', error);
    if (error.name === 'TypeError') {
      throw new Error("Network error: The API proxy might be down.");
    }
    throw error;
  }
}

export async function fetchServiceDetails(serviceUid: string, runDate: string): Promise<ServiceDetail> {
  // runDate is usually YYYY/MM/DD in RTT API URL
  const formattedDate = runDate.replace(/-/g, '/');
  const targetUrl = `https://api.rtt.io/api/v1/json/service/${serviceUid}/${formattedDate}`;
  const proxiedUrl = `https://corsproxy.io/?${encodeURIComponent(targetUrl)}`;

  try {
    const response = await fetch(proxiedUrl, {
      method: 'GET',
      headers: {
        'Authorization': getAuthHeader(),
        'Accept': 'application/json'
      }
    });

    if (!response.ok) {
      throw new Error(`Service Detail Error (${response.status})`);
    }

    return await response.json();
  } catch (error: any) {
    console.error('RTT Service Detail Error:', error);
    throw error;
  }
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse, ServiceDetail, LocationDetail } from './types';
import { fetchDepartures, fetchServiceDetails } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<ServiceDetail | null>(null);
  const [isServiceLoading, setIsServiceLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);

  const latestQueryRef = useRef('');

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      setSearchError(null);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      setSearchError(null);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
          if (!results || results.length === 0) {
             setSearchError("No stations found");
          }
        }
      } catch (err) {
        console.error("Search error:", err);
        if (latestQueryRef.current === searchQuery) {
          setSearchError("Lookup service unavailable");
        }
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const getStationName = (obj: any): string => {
    if (!obj) return "";
    if (Array.isArray(obj)) {
      if (obj.length === 0) return "";
      return getStationName(obj[obj.length - 1]);
    }
    return obj.description || obj.locationName || obj.publicName || obj.name || obj.crs || "";
  };

  const getFullDestinationName = (service: Service): string => {
    let name = getStationName(service.destination);
    if (!name && service.locationDetail) {
      name = getStationName(service.locationDetail.destination);
    }
    return name || "Check Board";
  };

  const loadStationData = useCallback(async (station: Station, silent: boolean = false) => {
    if (!station || !station.crs) return;

    if (!silent) {
      setLoading(true);
      setDepartures([]);
      setSelectedService(null);
    }

    setEnriching(false);
    setError(null);
    setSelectedStation(station);
    setSearchQuery('');

    try {
      const data = await fetchDepartures(station.crs);
      const services = Array.isArray(data.services) ? data.services : [];

      setDepartures(services);
      setLastUpdated(new Date());

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 15).map(s => ({
          origin: getStationName(s.origin) || "Origin",
          destination: getFullDestinationName(s),
          via: station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults || enrichedResults.length === 0) return;

          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || 
              destName.includes(r.destination.toLowerCase())
            );

            if (match && match.stops.length > 0) {
              return { ...s, callingPoints: match.stops };
            }
            return s;
          }));
        }).catch(err => {
          console.warn("Failed to fetch calling points:", err);
        }).finally(() => {
          setEnriching(false);
        });
      }

    } catch (err: any) {
      console.error(err);
      if (!silent) {
        setError(err.message || "An unexpected error occurred.");
      }
    } finally {
      if (!silent) {
        setLoading(false);
      }
    }
  }, []);

  const handleServiceClick = async (service: Service) => {
    setIsServiceLoading(true);
    try {
      const details = await fetchServiceDetails(service.serviceUid, service.runDate);
      setSelectedService(details);
    } catch (err: any) {
      alert("Failed to load service details: " + err.message);
    } finally {
      setIsServiceLoading(false);
    }
  };

  // Automatic Refresh Logic: Every 30 seconds
  useEffect(() => {
    if (!selectedStation) return;

    const interval = setInterval(() => {
      loadStationData(selectedStation, true);
    }, 30000);

    return () => clearInterval(interval);
  }, [selectedStation, loadStationData]);

  const calculateStatus = (location: LocationDetail) => {
    const planned = location.gbttBookedDeparture || location.gbttBookedArrival;
    const actual = location.realtimeDeparture || location.realtimeArrival;

    if (!planned) return { text: "Scheduled", color: "text-blue-400", bg: "bg-blue-400/10" };
    if (!actual || actual === planned) return { text: "On Time", color: "text-emerald-400", bg: "bg-emerald-400/10" }; 

    try {
      const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
      const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
      let diff = aMin - pMin;
      if (diff < -1200) diff += 1440;
      if (diff > 1200) diff -= 1440;

      if (diff <= 0) return { text: "On Time", color: "text-emerald-400", bg: "bg-emerald-400/10" };
      if (diff > 59) return { text: "Delayed", color: "text-rose-400", bg: "bg-rose-400/10" };
      return { text: `${diff}m Late`, color: "text-orange-400", bg: "bg-orange-400/10" };
    } catch (e) {
      return { text: "Live", color: "text-blue-400", bg: "bg-blue-400/10" };
    }
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr || timeStr.length < 4) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  const resetToSearch = () => {
    setSelectedStation(null);
    setDepartures([]);
    setSearchQuery('');
    setSearchError(null);
    setLastUpdated(null);
    setSelectedService(null);
  };

  const closeServiceDetail = () => setSelectedService(null);

  if (!selectedStation) {
    return (
      <div className="min-h-screen text-slate-200 flex flex-col items-center justify-start pt-6 md:pt-12 p-4 sm:p-6 transition-all bg-[#0b1120]">
        <div className="w-full max-w-xl animate-in fade-in slide-in-from-bottom-2 duration-700">
          <header className="mb-4 flex items-center justify-center gap-3">
            <div className="p-1.5 bg-blue-600 rounded-xl text-white shadow-lg">
              <Icons.Train />
            </div>
            <div className="text-left">
              <h1 className="text-xl md:text-2xl font-black tracking-tighter text-white italic uppercase leading-none">UK Rail Live</h1>
              <p className="text-slate-500 text-[8px] font-black uppercase tracking-[0.3em]">Real-time Departures</p>
            </div>
          </header>

          <div className="relative group">
            <div className="relative bg-slate-900 border border-slate-700 rounded-xl p-0.5 shadow-xl">
              <div className="relative flex items-center">
                <div className="absolute left-4 text-slate-500 scale-75">
                  {isSearching ? <div className="animate-spin h-4 w-4 border-2 border-blue-500 border-t-transparent rounded-full" /> : <Icons.Search />}
                </div>
                <input
                  type="text"
                  className="w-full pl-11 pr-4 py-2.5 bg-transparent text-white placeholder-slate-500 focus:outline-none text-base md:text-lg font-bold"
                  placeholder="Enter station name..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  autoFocus
                />
              </div>

              {searchError && (
                <div className="px-4 py-2 text-[10px] font-black text-rose-500 uppercase tracking-widest border-t border-slate-800 bg-rose-500/5">
                   {searchError}
                </div>
              )}

              {searchResults.length > 0 && (
                <div className="mt-0.5 border-t border-slate-800 max-h-64 overflow-y-auto no-scrollbar">
                  {searchResults.map((s) => (
                    <button
                      key={s.crs}
                      onClick={() => loadStationData(s)}
                      className="w-full flex items-center justify-between p-2.5 hover:bg-white/5 text-left transition-colors group"
                    >
                      <div className="flex items-baseline gap-2">
                        <div className="font-bold text-white group-hover:text-blue-400 text-sm md:text-base">{s.name}</div>
                        <div className="text-[9px] text-slate-600 uppercase font-black tracking-widest">{s.crs}</div>
                      </div>
                      <div className="text-slate-800 group-hover:text-blue-500 scale-75">
                        <Icons.ChevronRight />
                      </div>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>

          {!searchResults.length && !searchQuery && (
            <div className="mt-4">
              <div className="flex items-center gap-3 mb-3">
                <div className="h-px bg-slate-800 flex-1"></div>
                <h3 className="text-[8px] font-black text-slate-600 uppercase tracking-[0.4em]">Popular Hubs</h3>
                <div className="h-px bg-slate-800 flex-1"></div>
              </div>
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-1.5">
                {MAJOR_STATIONS.map((s) => (
                  <button
                    key={s.crs}
                    onClick={() => loadStationData(s)}
                    className="px-2 py-1.5 bg-slate-900/40 border border-slate-800/50 hover:border-blue-500/50 hover:bg-slate-800 text-slate-400 hover:text-white rounded-lg text-[9px] font-bold transition-all truncate"
                  >
                    {s.name}
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-slate-100 selection:bg-blue-500/30">
      <nav className="fixed top-0 left-0 right-0 z-50 bg-black/90 backdrop-blur-xl border-b border-white/10 px-4 md:px-8 py-2 md:py-3 flex items-center justify-between">
        <div className="flex items-center gap-4">
          {selectedService && (
             <button 
               onClick={closeServiceDetail}
               className="p-2 hover:bg-white/5 rounded-full text-slate-400 hover:text-white transition-colors"
             >
                <div className="rotate-180 scale-125"><Icons.ChevronRight /></div>
             </button>
          )}
          <div className="flex flex-col">
             <div className="flex items-center gap-2">
                <span className="text-blue-500 font-black tracking-widest text-[9px] uppercase">{selectedStation.crs}</span>
                <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
             </div>
             <h1 className="text-lg md:text-2xl font-black tracking-tighter uppercase italic leading-none truncate max-w-[150px] sm:max-w-none">
               {selectedService ? selectedService.trainIdentity : selectedStation.name}
             </h1>
          </div>
        </div>

        <div className="flex items-center gap-4 md:gap-8">
           <div className="flex flex-col items-end opacity-90">
             <span className="text-[6px] md:text-[8px] font-black text-emerald-500/40 uppercase tracking-[0.3em] mb-0.5">Last Load</span>
             <div className="mono text-emerald-400 text-xs md:text-xl font-bold tracking-[0.15em] drop-shadow-[0_0_8px_rgba(52,211,153,0.6)] bg-emerald-500/5 px-2 py-0.5 rounded border border-emerald-500/10">
               {lastUpdated ? lastUpdated.toLocaleTimeString('en-GB', { hour12: false }) : "--:--:--"}
             </div>
           </div>

           <button 
             onClick={resetToSearch}
             className="flex items-center gap-2 px-3 py-1.5 md:px-5 md:py-2 bg-white text-black hover:bg-slate-200 rounded-full font-black text-[9px] md:text-xs uppercase tracking-widest transition-all shadow-lg active:scale-95 whitespace-nowrap"
           >
             <Icons.Search />
             <span className="hidden sm:inline">Search</span>
           </button>
        </div>
      </nav>

      <main className="pt-16 md:pt-20 pb-4 px-1 sm:px-2 md:px-6 max-w-[1500px] mx-auto animate-in fade-in zoom-in-95 duration-500">
        <div className="rounded-xl md:rounded-2xl bg-[#0c0c0c] border border-white/5 shadow-2xl overflow-hidden relative min-h-[400px]">

          {/* Main Departure Board */}
          {!selectedService && (
            <>
              <div className="hidden md:grid grid-cols-12 gap-4 px-6 py-2 bg-zinc-900/50 border-b border-white/5 text-[8px] font-black uppercase tracking-[0.4em] text-zinc-500">
                <div className="col-span-2">Scheduled</div>
                <div className="col-span-10">Service Details</div>
              </div>

              <div className="divide-y divide-white/5">
                {loading || isServiceLoading ? (
                  <div className="p-32 text-center flex flex-col items-center gap-6">
                    <div className="relative">
                      <div className="h-16 w-16 border-[4px] border-blue-500/10 border-t-blue-500 rounded-full animate-spin" />
                    </div>
                    <div className="text-slate-500 font-black text-[9px] tracking-[0.4em] uppercase animate-pulse">Scanning Platform...</div>
                  </div>
                ) : error ? (
                  <div className="p-16 text-center space-y-6">
                    <div className="text-rose-500 text-4xl">⚠️</div>
                    <div className="space-y-2">
                      <h3 className="text-white font-black text-xl italic uppercase">Connection Error</h3>
                      <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">{error}</p>
                    </div>
                    <button 
                      onClick={() => loadStationData(selectedStation)}
                      className="px-8 py-3 bg-white text-black rounded-xl font-black uppercase tracking-widest text-xs"
                    >
                      Retry
                    </button>
                  </div>
                ) : departures.length === 0 ? (
                  <div className="p-32 text-center">
                    <div className="text-slate-700 font-black text-2xl uppercase italic opacity-20 tracking-tighter mb-2">BOARD CLEAR</div>
                    <div className="text-slate-600 text-[8px] font-black uppercase tracking-[0.2em]">No services found.</div>
                  </div>
                ) : (
                  departures.map((service, idx) => {
                    const status = calculateStatus(service.locationDetail);
                    const destinationName = getFullDestinationName(service);
                    const scheduledTime = service.locationDetail?.gbttBookedDeparture || service.locationDetail?.gbttBookedArrival;
                    const expectedTime = service.locationDetail?.realtimeDeparture || service.locationDetail?.realtimeArrival;

                    return (
                      <button 
                        key={`${service.serviceUid}-${idx}`}
                        onClick={() => handleServiceClick(service)}
                        className="w-full text-left grid grid-cols-12 gap-2 md:gap-4 px-4 md:px-6 py-3 md:py-4 items-start md:items-center hover:bg-white/[0.03] transition-colors group relative border-none appearance-none"
                      >
                        <div className="col-span-3 md:col-span-2 flex flex-col">
                          <div className="text-2xl md:text-4xl font-black mono text-white leading-none tracking-tighter group-hover:text-blue-500 transition-colors">
                            {formatTime(scheduledTime)}
                          </div>
                          {status.text !== "On Time" && expectedTime && (
                            <div className="text-[9px] md:text-[10px] font-black text-blue-400 mono mt-1">
                              EXP {formatTime(expectedTime)}
                            </div>
                          )}
                        </div>

                        <div className="col-span-9 md:col-span-10">
                          <div className="flex flex-wrap items-center gap-x-3 gap-y-1 mb-1">
                            <div className="text-lg md:text-2xl font-black text-slate-100 uppercase tracking-tight leading-tight truncate group-hover:translate-x-1 transition-transform">
                              {destinationName}
                            </div>
                            <div className={`inline-block text-[8px] md:text-[10px] font-black uppercase tracking-[0.1em] px-2 py-0.5 rounded border border-white/5 ${status.bg} ${status.color}`}>
                              {status.text}
                            </div>
                          </div>

                          <div className="flex flex-wrap items-center gap-x-2 gap-y-1">
                             {service.callingPoints ? (
                               <>
                                 <span className="text-[7px] md:text-[8px] font-black text-slate-700 uppercase tracking-widest bg-white/5 px-1.5 py-0.5 rounded">Via:</span>
                                 <div className="flex items-center gap-1.5 overflow-hidden">
                                   {service.callingPoints.map((stop, sIdx) => (
                                     <React.Fragment key={sIdx}>
                                       <span className="text-[9px] md:text-[10px] font-medium text-slate-400 group-hover:text-slate-300 transition-colors cursor-default whitespace-nowrap">
                                         {stop}
                                       </span>
                                       {sIdx < service.callingPoints!.length - 1 && (
                                         <div className="w-0.5 h-0.5 bg-slate-800 rounded-full" />
                                       )}
                                     </React.Fragment>
                                   ))}
                                 </div>
                               </>
                             ) : enriching ? (
                               <div className="flex gap-2 items-center animate-pulse opacity-40">
                                 <div className="h-2 w-8 bg-white/10 rounded" />
                                 <div className="h-2 w-12 bg-white/10 rounded" />
                               </div>
                             ) : (
                               <span className="text-[8px] text-blue-500/20 font-black uppercase tracking-[0.2em] italic">Express Service</span>
                             )}

                             <span className="ml-auto text-[7px] md:text-[8px] text-zinc-700 font-black uppercase tracking-widest hidden md:block">
                              {service.atocName || "National Rail"}
                             </span>
                          </div>
                        </div>
                      </button>
                    );
                  })
                )}
              </div>
            </>
          )}

          {/* Service Journey Detail View */}
          {selectedService && (
            <div className="p-4 md:p-8 animate-in fade-in slide-in-from-right-4 duration-500">
              <header className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-4 border-b border-white/5 pb-6">
                <div>
                  <div className="flex items-center gap-3 mb-2">
                    <span className="text-[10px] font-black text-blue-500 uppercase tracking-[0.4em]">{selectedService.trainIdentity}</span>
                    <span className="px-2 py-0.5 bg-zinc-800 rounded text-[8px] font-black text-zinc-400 uppercase tracking-widest">{selectedService.atocName}</span>
                  </div>
                  <h2 className="text-3xl md:text-5xl font-black italic uppercase tracking-tighter text-white">
                    Journey Timeline
                  </h2>
                </div>
                <div className="text-right">
                  <span className="text-[9px] font-black text-slate-600 uppercase tracking-[0.3em]">Operational Date</span>
                  <div className="text-lg font-bold text-slate-400 uppercase">{selectedService.runDate}</div>
                </div>
              </header>

              <div className="max-w-4xl mx-auto space-y-0.5 relative">
                {/* Timeline vertical bar */}
                <div className="absolute left-[2.4rem] md:left-[3.4rem] top-6 bottom-6 w-0.5 bg-zinc-900 z-0" />

                {selectedService.locations.map((loc, lIdx) => {
                  const status = calculateStatus(loc);
                  const isOrigin = lIdx === 0;
                  const isDestination = lIdx === selectedService.locations.length - 1;
                  const isCurrent = loc.crs === selectedStation.crs;
                  const time = loc.gbttBookedArrival || loc.gbttBookedDeparture;
                  const actual = loc.realtimeArrival || loc.realtimeDeparture;

                  return (
                    <div 
                      key={`${loc.crs}-${lIdx}`} 
                      className={`relative flex items-center gap-6 md:gap-10 py-4 px-2 rounded-xl transition-all ${isCurrent ? 'bg-blue-600/5 border border-blue-500/20' : 'hover:bg-white/[0.02]'}`}
                    >
                      {/* Timeline Dot */}
                      <div className="flex flex-col items-center z-10 w-16 md:w-24">
                         <div className={`mono text-[10px] md:text-xs font-bold ${isCurrent ? 'text-blue-400' : 'text-slate-500'}`}>
                           {formatTime(time)}
                         </div>
                         <div className={`mt-2 h-4 w-4 rounded-full border-2 bg-black transition-all ${isCurrent ? 'border-blue-500 scale-125 shadow-[0_0_10px_rgba(59,130,246,0.5)]' : 'border-zinc-800'}`} />
                      </div>

                      {/* Content */}
                      <div className="flex-1 flex flex-col md:flex-row md:items-center justify-between gap-2">
                        <div>
                          <div className="flex items-center gap-2">
                            <span className={`text-base md:text-xl font-black uppercase tracking-tight ${isCurrent ? 'text-blue-400' : 'text-slate-200'}`}>
                              {loc.description}
                            </span>
                            <span className="text-[8px] font-black text-slate-600 tracking-widest uppercase">{loc.crs}</span>
                          </div>
                          <div className="flex items-center gap-3 mt-1">
                            {loc.platform && (
                              <span className="px-1.5 py-0.5 bg-zinc-900 border border-zinc-800 rounded text-[9px] font-black text-zinc-500 uppercase tracking-widest">
                                PLAT {loc.platform}
                              </span>
                            )}
                            <span className={`text-[9px] md:text-[10px] font-black uppercase tracking-widest ${status.color}`}>
                              {status.text === "On Time" ? (actual ? 'Arrived On Time' : 'On Time') : status.text}
                            </span>
                          </div>
                        </div>

                        <div className="flex items-center gap-4">
                           {actual && actual !== time && (
                             <div className="flex flex-col items-end">
                               <span className="text-[7px] font-black text-slate-700 uppercase tracking-widest">Realtime</span>
                               <span className="mono text-blue-400 font-bold text-xs md:text-sm">{formatTime(actual)}</span>
                             </div>
                           )}
                           {isOrigin && <span className="text-[8px] font-black bg-emerald-500/10 text-emerald-500 px-2 py-1 rounded border border-emerald-500/10 uppercase tracking-[0.2em]">Origin</span>}
                           {isDestination && <span className="text-[8px] font-black bg-rose-500/10 text-rose-500 px-2 py-1 rounded border border-rose-500/10 uppercase tracking-[0.2em]">Dest</span>}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>

              <div className="mt-12 flex justify-center">
                 <button 
                   onClick={closeServiceDetail}
                   className="px-8 py-3 bg-zinc-900 border border-zinc-800 hover:bg-white hover:text-black transition-all rounded-full font-black uppercase tracking-[0.4em] text-[10px] shadow-xl"
                 >
                   Back to Board
                 </button>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="px-6 py-4 flex flex-col md:flex-row justify-between items-center gap-2 border-t border-white/5 opacity-40">
         <div className="flex items-center gap-6 text-[8px] font-black uppercase tracking-[0.2em] text-zinc-600">
            <span className="flex items-center gap-1.5"><span className="w-1.5 h-1.5 rounded-full bg-blue-600" /> LIVE DATA</span>
            <span>GEMINI ENGINE</span>
            <span className="flex items-center gap-1.5 animate-pulse"><span className="w-1 h-1 rounded-full bg-emerald-500" /> AUTO-REFRESHING (30s)</span>
         </div>
         <div className="text-[8px] font-black uppercase tracking-[0.2em] text-zinc-800">
           {selectedService ? 'DETAILED VIEW' : 'BOARD ACTIVE'}
         </div>
      </footer>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }

        @media (orientation: landscape) and (max-height: 600px) {
           nav { padding-top: 0.25rem; padding-bottom: 0.25rem; }
           .pt-16 { padding-top: 3rem; }
           .py-3 { padding-top: 0.5rem; padding-bottom: 0.5rem; }
           .text-2xl { font-size: 1.15rem; }
           .text-lg { font-size: 0.95rem; }
        }

        @media (min-height: 700px) {
           .py-4 { padding-top: 1rem; padding-bottom: 1rem; }
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse, ServiceDetail, LocationDetail } from './types';
import { fetchDepartures, fetchServiceDetails } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<ServiceDetail | null>(null);
  const [isServiceLoading, setIsServiceLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);

  const latestQueryRef = useRef('');

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      setSearchError(null);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      setSearchError(null);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
          if (!results || results.length === 0) {
             setSearchError("No stations found");
          }
        }
      } catch (err) {
        console.error("Search error:", err);
        if (latestQueryRef.current === searchQuery) {
          setSearchError("Lookup service unavailable");
        }
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const getStationName = (obj: any): string => {
    if (!obj) return "";
    if (Array.isArray(obj)) {
      if (obj.length === 0) return "";
      return getStationName(obj[obj.length - 1]);
    }
    return obj.description || obj.locationName || obj.publicName || obj.name || obj.crs || "";
  };

  const getFullDestinationName = (service: Service): string => {
    let name = getStationName(service.destination);
    if (!name && service.locationDetail) {
      name = getStationName(service.locationDetail.destination);
    }
    return name || "Check Board";
  };

  const loadStationData = useCallback(async (station: Station, silent: boolean = false) => {
    if (!station || !station.crs) return;

    if (!silent) {
      setLoading(true);
      setDepartures([]);
      setSelectedService(null);
    }

    setEnriching(false);
    setError(null);
    setSelectedStation(station);
    setSearchQuery('');

    try {
      const data = await fetchDepartures(station.crs);
      const services = Array.isArray(data.services) ? data.services : [];

      setDepartures(services);
      setLastUpdated(new Date());

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 15).map(s => ({
          origin: getStationName(s.origin) || "Origin",
          destination: getFullDestinationName(s),
          via: station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults || enrichedResults.length === 0) return;

          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || 
              destName.includes(r.destination.toLowerCase())
            );

            if (match && match.stops.length > 0) {
              return { ...s, callingPoints: match.stops };
            }
            return s;
          }));
        }).catch(err => {
          console.warn("Failed to fetch calling points:", err);
        }).finally(() => {
          setEnriching(false);
        });
      }

    } catch (err: any) {
      console.error(err);
      if (!silent) {
        setError(err.message || "An unexpected error occurred.");
      }
    } finally {
      if (!silent) {
        setLoading(false);
      }
    }
  }, []);

  const handleServiceClick = async (service: Service) => {
    setIsServiceLoading(true);
    try {
      const details = await fetchServiceDetails(service.serviceUid, service.runDate);
      setSelectedService(details);
    } catch (err: any) {
      alert("Failed to load service details: " + err.message);
    } finally {
      setIsServiceLoading(false);
    }
  };

  // Automatic Refresh Logic: Every 30 seconds
  useEffect(() => {
    if (!selectedStation) return;

    const interval = setInterval(() => {
      loadStationData(selectedStation, true);
    }, 30000);

    return () => clearInterval(interval);
  }, [selectedStation, loadStationData]);

  const calculateStatus = (location: LocationDetail) => {
    const planned = location.gbttBookedDeparture || location.gbttBookedArrival;
    const actual = location.realtimeDeparture || location.realtimeArrival;

    if (!planned) return { text: "Scheduled", color: "text-blue-400", bg: "bg-blue-400/10" };
    if (!actual || actual === planned) return { text: "On Time", color: "text-emerald-400", bg: "bg-emerald-400/10" }; 

    try {
      const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
      const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
      let diff = aMin - pMin;
      if (diff < -1200) diff += 1440;
      if (diff > 1200) diff -= 1440;

      if (diff <= 0) return { text: "On Time", color: "text-emerald-400", bg: "bg-emerald-400/10" };
      if (diff > 59) return { text: "Delayed", color: "text-rose-400", bg: "bg-rose-400/10" };
      return { text: `${diff}m Late`, color: "text-orange-400", bg: "bg-orange-400/10" };
    } catch (e) {
      return { text: "Live", color: "text-blue-400", bg: "bg-blue-400/10" };
    }
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr || timeStr.length < 4) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  const resetToSearch = () => {
    setSelectedStation(null);
    setDepartures([]);
    setSearchQuery('');
    setSearchError(null);
    setLastUpdated(null);
    setSelectedService(null);
  };

  const closeServiceDetail = () => setSelectedService(null);

  if (!selectedStation) {
    return (
      <div className="min-h-screen text-slate-200 flex flex-col items-center justify-start pt-6 md:pt-12 p-4 sm:p-6 transition-all bg-[#0b1120]">
        <div className="w-full max-w-xl animate-in fade-in slide-in-from-bottom-2 duration-700">
          <header className="mb-4 flex items-center justify-center gap-3">
            <div className="p-1.5 bg-blue-600 rounded-xl text-white shadow-lg">
              <Icons.Train />
            </div>
            <div className="text-left">
              <h1 className="text-xl md:text-2xl font-black tracking-tighter text-white italic uppercase leading-none">UK Rail Live</h1>
              <p className="text-slate-500 text-[8px] font-black uppercase tracking-[0.3em]">Real-time Departures</p>
            </div>
          </header>

          <div className="relative group">
            <div className="relative bg-slate-900 border border-slate-700 rounded-xl p-0.5 shadow-xl">
              <div className="relative flex items-center">
                <div className="absolute left-4 text-slate-500 scale-75">
                  {isSearching ? <div className="animate-spin h-4 w-4 border-2 border-blue-500 border-t-transparent rounded-full" /> : <Icons.Search />}
                </div>
                <input
                  type="text"
                  className="w-full pl-11 pr-4 py-2.5 bg-transparent text-white placeholder-slate-500 focus:outline-none text-base md:text-lg font-bold"
                  placeholder="Enter station name..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  autoFocus
                />
              </div>

              {searchError && (
                <div className="px-4 py-2 text-[10px] font-black text-rose-500 uppercase tracking-widest border-t border-slate-800 bg-rose-500/5">
                   {searchError}
                </div>
              )}

              {searchResults.length > 0 && (
                <div className="mt-0.5 border-t border-slate-800 max-h-64 overflow-y-auto no-scrollbar">
                  {searchResults.map((s) => (
                    <button
                      key={s.crs}
                      onClick={() => loadStationData(s)}
                      className="w-full flex items-center justify-between p-2.5 hover:bg-white/5 text-left transition-colors group"
                    >
                      <div className="flex items-baseline gap-2">
                        <div className="font-bold text-white group-hover:text-blue-400 text-sm md:text-base">{s.name}</div>
                        <div className="text-[9px] text-slate-600 uppercase font-black tracking-widest">{s.crs}</div>
                      </div>
                      <div className="text-slate-800 group-hover:text-blue-500 scale-75">
                        <Icons.ChevronRight />
                      </div>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>

          {!searchResults.length && !searchQuery && (
            <div className="mt-4">
              <div className="flex items-center gap-3 mb-3">
                <div className="h-px bg-slate-800 flex-1"></div>
                <h3 className="text-[8px] font-black text-slate-600 uppercase tracking-[0.4em]">Popular Hubs</h3>
                <div className="h-px bg-slate-800 flex-1"></div>
              </div>
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-1.5">
                {MAJOR_STATIONS.map((s) => (
                  <button
                    key={s.crs}
                    onClick={() => loadStationData(s)}
                    className="px-2 py-1.5 bg-slate-900/40 border border-slate-800/50 hover:border-blue-500/50 hover:bg-slate-800 text-slate-400 hover:text-white rounded-lg text-[9px] font-bold transition-all truncate"
                  >
                    {s.name}
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-slate-100 selection:bg-blue-500/30">
      <nav className="fixed top-0 left-0 right-0 z-50 bg-black/90 backdrop-blur-xl border-b border-white/10 px-4 md:px-8 py-2 md:py-3 flex items-center justify-between">
        <div className="flex items-center gap-4">
          {selectedService && (
             <button 
               onClick={closeServiceDetail}
               className="p-2 hover:bg-white/5 rounded-full text-slate-400 hover:text-white transition-colors"
             >
                <div className="rotate-180 scale-125"><Icons.ChevronRight /></div>
             </button>
          )}
          <div className="flex flex-col">
             <div className="flex items-center gap-2">
                <span className="text-blue-500 font-black tracking-widest text-[9px] uppercase">{selectedStation.crs}</span>
                <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
             </div>
             <h1 className="text-lg md:text-2xl font-black tracking-tighter uppercase italic leading-none truncate max-w-[150px] sm:max-w-none">
               {selectedService ? selectedService.trainIdentity : selectedStation.name}
             </h1>
          </div>
        </div>

        <div className="flex items-center gap-4 md:gap-8">
           <div className="flex flex-col items-end opacity-90">
             <span className="text-[6px] md:text-[8px] font-black text-emerald-500/40 uppercase tracking-[0.3em] mb-0.5">Last Load</span>
             <div className="mono text-emerald-400 text-xs md:text-xl font-bold tracking-[0.15em] drop-shadow-[0_0_8px_rgba(52,211,153,0.6)] bg-emerald-500/5 px-2 py-0.5 rounded border border-emerald-500/10">
               {lastUpdated ? lastUpdated.toLocaleTimeString('en-GB', { hour12: false }) : "--:--:--"}
             </div>
           </div>

           <button 
             onClick={resetToSearch}
             className="flex items-center gap-2 px-3 py-1.5 md:px-5 md:py-2 bg-white text-black hover:bg-slate-200 rounded-full font-black text-[9px] md:text-xs uppercase tracking-widest transition-all shadow-lg active:scale-95 whitespace-nowrap"
           >
             <Icons.Search />
             <span className="hidden sm:inline">Search</span>
           </button>
        </div>
      </nav>

      <main className="pt-16 md:pt-20 pb-4 px-1 sm:px-2 md:px-6 max-w-[1500px] mx-auto animate-in fade-in zoom-in-95 duration-500">
        <div className="rounded-xl md:rounded-2xl bg-[#0c0c0c] border border-white/5 shadow-2xl overflow-hidden relative min-h-[400px]">

          {/* Main Departure Board */}
          {!selectedService && (
            <>
              <div className="hidden md:grid grid-cols-12 gap-4 px-6 py-2 bg-zinc-900/50 border-b border-white/5 text-[8px] font-black uppercase tracking-[0.4em] text-zinc-500">
                <div className="col-span-2">Scheduled</div>
                <div className="col-span-10">Service Details</div>
              </div>

              <div className="divide-y divide-white/5">
                {loading || isServiceLoading ? (
                  <div className="p-32 text-center flex flex-col items-center gap-6">
                    <div className="relative">
                      <div className="h-16 w-16 border-[4px] border-blue-500/10 border-t-blue-500 rounded-full animate-spin" />
                    </div>
                    <div className="text-slate-500 font-black text-[9px] tracking-[0.4em] uppercase animate-pulse">Scanning Platform...</div>
                  </div>
                ) : error ? (
                  <div className="p-16 text-center space-y-6">
                    <div className="text-rose-500 text-4xl">⚠️</div>
                    <div className="space-y-2">
                      <h3 className="text-white font-black text-xl italic uppercase">Connection Error</h3>
                      <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">{error}</p>
                    </div>
                    <button 
                      onClick={() => loadStationData(selectedStation)}
                      className="px-8 py-3 bg-white text-black rounded-xl font-black uppercase tracking-widest text-xs"
                    >
                      Retry
                    </button>
                  </div>
                ) : departures.length === 0 ? (
                  <div className="p-32 text-center">
                    <div className="text-slate-700 font-black text-2xl uppercase italic opacity-20 tracking-tighter mb-2">BOARD CLEAR</div>
                    <div className="text-slate-600 text-[8px] font-black uppercase tracking-[0.2em]">No services found.</div>
                  </div>
                ) : (
                  departures.map((service, idx) => {
                    const status = calculateStatus(service.locationDetail);
                    const destinationName = getFullDestinationName(service);
                    const scheduledTime = service.locationDetail?.gbttBookedDeparture || service.locationDetail?.gbttBookedArrival;
                    const expectedTime = service.locationDetail?.realtimeDeparture || service.locationDetail?.realtimeArrival;

                    return (
                      <button 
                        key={`${service.serviceUid}-${idx}`}
                        onClick={() => handleServiceClick(service)}
                        className="w-full text-left grid grid-cols-12 gap-2 md:gap-4 px-4 md:px-6 py-3 md:py-4 items-start md:items-center hover:bg-white/[0.03] transition-colors group relative border-none appearance-none"
                      >
                        <div className="col-span-3 md:col-span-2 flex flex-col">
                          <div className="text-2xl md:text-4xl font-black mono text-white leading-none tracking-tighter group-hover:text-blue-500 transition-colors">
                            {formatTime(scheduledTime)}
                          </div>
                          {status.text !== "On Time" && expectedTime && (
                            <div className="text-[9px] md:text-[10px] font-black text-blue-400 mono mt-1">
                              EXP {formatTime(expectedTime)}
                            </div>
                          )}
                        </div>

                        <div className="col-span-9 md:col-span-10">
                          <div className="flex flex-wrap items-center gap-x-3 gap-y-1 mb-1">
                            <div className="text-lg md:text-2xl font-black text-slate-100 uppercase tracking-tight leading-tight truncate group-hover:translate-x-1 transition-transform">
                              {destinationName}
                            </div>
                            <div className={`inline-block text-[8px] md:text-[10px] font-black uppercase tracking-[0.1em] px-2 py-0.5 rounded border border-white/5 ${status.bg} ${status.color}`}>
                              {status.text}
                            </div>
                          </div>

                          <div className="flex flex-wrap items-center gap-x-2 gap-y-1">
                             {service.callingPoints ? (
                               <>
                                 <span className="text-[7px] md:text-[8px] font-black text-slate-700 uppercase tracking-widest bg-white/5 px-1.5 py-0.5 rounded">Via:</span>
                                 <div className="flex items-center gap-1.5 overflow-hidden">
                                   {service.callingPoints.map((stop, sIdx) => (
                                     <React.Fragment key={sIdx}>
                                       <span className="text-[9px] md:text-[10px] font-medium text-slate-400 group-hover:text-slate-300 transition-colors cursor-default whitespace-nowrap">
                                         {stop}
                                       </span>
                                       {sIdx < service.callingPoints!.length - 1 && (
                                         <div className="w-0.5 h-0.5 bg-slate-800 rounded-full" />
                                       )}
                                     </React.Fragment>
                                   ))}
                                 </div>
                               </>
                             ) : enriching ? (
                               <div className="flex gap-2 items-center animate-pulse opacity-40">
                                 <div className="h-2 w-8 bg-white/10 rounded" />
                                 <div className="h-2 w-12 bg-white/10 rounded" />
                               </div>
                             ) : (
                               <span className="text-[8px] text-blue-500/20 font-black uppercase tracking-[0.2em] italic">Express Service</span>
                             )}

                             <span className="ml-auto text-[7px] md:text-[8px] text-zinc-700 font-black uppercase tracking-widest hidden md:block">
                              {service.atocName || "National Rail"}
                             </span>
                          </div>
                        </div>
                      </button>
                    );
                  })
                )}
              </div>
            </>
          )}

          {/* Service Journey Detail View */}
          {selectedService && (
            <div className="p-4 md:p-6 animate-in fade-in slide-in-from-right-4 duration-500">
              <header className="mb-4 flex flex-row items-center justify-between gap-4 border-b border-white/5 pb-3">
                <div className="flex items-center gap-4">
                  <div className="flex flex-col">
                    <div className="flex items-center gap-2 mb-0.5">
                      <span className="text-[8px] font-black text-blue-500 uppercase tracking-[0.3em]">{selectedService.trainIdentity}</span>
                      <span className="px-1.5 py-0.5 bg-zinc-800 rounded text-[7px] font-black text-zinc-400 uppercase tracking-widest">{selectedService.atocName}</span>
                    </div>
                    <h2 className="text-xl md:text-3xl font-black italic uppercase tracking-tighter text-white leading-none">
                      Journey Timeline
                    </h2>
                  </div>
                </div>
                <div className="text-right flex flex-col items-end">
                  <span className="text-[7px] font-black text-slate-600 uppercase tracking-[0.3em]">Operational Date</span>
                  <div className="text-sm font-bold text-slate-400 uppercase leading-none mt-1">{selectedService.runDate}</div>
                </div>
              </header>

              <div className="max-w-4xl mx-auto space-y-0 relative">
                {/* Timeline vertical bar */}
                <div className="absolute left-[2.4rem] md:left-[3.4rem] top-6 bottom-6 w-0.5 bg-zinc-900 z-0" />

                {selectedService.locations.map((loc, lIdx) => {
                  const status = calculateStatus(loc);
                  const isOrigin = lIdx === 0;
                  const isDestination = lIdx === selectedService.locations.length - 1;
                  const isCurrent = loc.crs === selectedStation.crs;
                  const time = loc.gbttBookedArrival || loc.gbttBookedDeparture;
                  const actual = loc.realtimeArrival || loc.realtimeDeparture;

                  return (
                    <div 
                      key={`${loc.crs}-${lIdx}`} 
                      className={`relative flex items-center gap-4 md:gap-8 py-2 md:py-3 px-2 rounded-lg transition-all ${isCurrent ? 'bg-blue-600/5 border border-blue-500/10' : 'hover:bg-white/[0.01]'}`}
                    >
                      {/* Timeline Dot */}
                      <div className="flex flex-col items-center z-10 w-14 md:w-20">
                         <div className={`mono text-[9px] md:text-xs font-bold ${isCurrent ? 'text-blue-400' : 'text-slate-500'}`}>
                           {formatTime(time)}
                         </div>
                         <div className={`mt-1 h-3 w-3 rounded-full border-2 bg-black transition-all ${isCurrent ? 'border-blue-500 scale-110 shadow-[0_0_8px_rgba(59,130,246,0.4)]' : 'border-zinc-800'}`} />
                      </div>

                      {/* Content */}
                      <div className="flex-1 flex flex-col md:flex-row md:items-center justify-between gap-1">
                        <div>
                          <div className="flex items-center gap-2">
                            <span className={`text-sm md:text-lg font-black uppercase tracking-tight leading-tight ${isCurrent ? 'text-blue-400' : 'text-slate-200'}`}>
                              {loc.description}
                            </span>
                            <span className="text-[7px] font-black text-slate-700 tracking-widest uppercase">{loc.crs}</span>
                          </div>
                          <div className="flex items-center gap-3 mt-0.5">
                            {loc.platform && (
                              <span className="px-1 py-0.5 bg-zinc-900 border border-zinc-800 rounded text-[8px] font-black text-zinc-500 uppercase tracking-widest">
                                P{loc.platform}
                              </span>
                            )}
                            <span className={`text-[8px] md:text-[9px] font-black uppercase tracking-widest ${status.color}`}>
                              {status.text === "On Time" ? (actual ? 'Arrived On Time' : 'On Time') : status.text}
                            </span>
                          </div>
                        </div>

                        <div className="flex items-center gap-3">
                           {actual && actual !== time && (
                             <div className="flex flex-col items-end">
                               <span className="text-[6px] font-black text-slate-700 uppercase tracking-widest">Realtime</span>
                               <span className="mono text-blue-400 font-bold text-[10px] md:text-xs">{formatTime(actual)}</span>
                             </div>
                           )}
                           {isOrigin && <span className="text-[7px] font-black bg-emerald-500/5 text-emerald-500/80 px-1.5 py-0.5 rounded border border-emerald-500/10 uppercase tracking-widest">Origin</span>}
                           {isDestination && <span className="text-[7px] font-black bg-rose-500/5 text-rose-500/80 px-1.5 py-0.5 rounded border border-rose-500/10 uppercase tracking-widest">Dest</span>}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>

              <div className="mt-8 flex justify-center">
                 <button 
                   onClick={closeServiceDetail}
                   className="px-6 py-2 bg-zinc-900 border border-zinc-800 hover:bg-white hover:text-black transition-all rounded-full font-black uppercase tracking-[0.3em] text-[9px] shadow-lg"
                 >
                   Return to Board
                 </button>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="px-6 py-4 flex flex-col md:flex-row justify-between items-center gap-2 border-t border-white/5 opacity-40">
         <div className="flex items-center gap-6 text-[8px] font-black uppercase tracking-[0.2em] text-zinc-600">
            <span className="flex items-center gap-1.5"><span className="w-1.5 h-1.5 rounded-full bg-blue-600" /> LIVE DATA</span>
            <span>GEMINI ENGINE</span>
            <span className="flex items-center gap-1.5 animate-pulse"><span className="w-1 h-1 rounded-full bg-emerald-500" /> AUTO-REFRESHING (30s)</span>
         </div>
         <div className="text-[8px] font-black uppercase tracking-[0.2em] text-zinc-800">
           {selectedService ? 'DETAILED VIEW' : 'BOARD ACTIVE'}
         </div>
      </footer>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }

        @media (orientation: landscape) and (max-height: 600px) {
           nav { padding-top: 0.25rem; padding-bottom: 0.25rem; }
           .pt-16 { padding-top: 3rem; }
           .py-3 { padding-top: 0.5rem; padding-bottom: 0.5rem; }
           .text-2xl { font-size: 1.15rem; }
           .text-lg { font-size: 0.95rem; }
        }

        @media (min-height: 700px) {
           .py-4 { padding-top: 1rem; padding-bottom: 1rem; }
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse, ServiceDetail, LocationDetail } from './types';
import { fetchDepartures, fetchServiceDetails } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<ServiceDetail | null>(null);
  const [isServiceLoading, setIsServiceLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);

  const latestQueryRef = useRef('');

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      setSearchError(null);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      setSearchError(null);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
          if (!results || results.length === 0) {
             setSearchError("No stations found");
          }
        }
      } catch (err) {
        console.error("Search error:", err);
        if (latestQueryRef.current === searchQuery) {
          setSearchError("Lookup service unavailable");
        }
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const getStationName = (obj: any): string => {
    if (!obj) return "";
    if (Array.isArray(obj)) {
      if (obj.length === 0) return "";
      return getStationName(obj[obj.length - 1]);
    }
    return obj.description || obj.locationName || obj.publicName || obj.name || obj.crs || "";
  };

  const getFullDestinationName = (service: Service): string => {
    let name = getStationName(service.destination);
    if (!name && service.locationDetail) {
      name = getStationName(service.locationDetail.destination);
    }
    return name || "Check Board";
  };

  const loadStationData = useCallback(async (station: Station, silent: boolean = false) => {
    if (!station || !station.crs) return;

    if (!silent) {
      setLoading(true);
      setDepartures([]);
      setSelectedService(null);
    }

    setEnriching(false);
    setError(null);
    setSelectedStation(station);
    setSearchQuery('');

    try {
      const data = await fetchDepartures(station.crs);
      const services = Array.isArray(data.services) ? data.services : [];

      setDepartures(services);
      setLastUpdated(new Date());

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 15).map(s => ({
          origin: getStationName(s.origin) || "Origin",
          destination: getFullDestinationName(s),
          via: station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults || enrichedResults.length === 0) return;

          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || 
              destName.includes(r.destination.toLowerCase())
            );

            if (match && match.stops.length > 0) {
              return { ...s, callingPoints: match.stops };
            }
            return s;
          }));
        }).catch(err => {
          console.warn("Failed to fetch calling points:", err);
        }).finally(() => {
          setEnriching(false);
        });
      }

    } catch (err: any) {
      console.error(err);
      if (!silent) {
        setError(err.message || "An unexpected error occurred.");
      }
    } finally {
      if (!silent) {
        setLoading(false);
      }
    }
  }, []);

  const handleServiceClick = async (service: Service) => {
    setIsServiceLoading(true);
    try {
      const details = await fetchServiceDetails(service.serviceUid, service.runDate);
      setSelectedService(details);
    } catch (err: any) {
      alert("Failed to load service details: " + err.message);
    } finally {
      setIsServiceLoading(false);
    }
  };

  // Automatic Refresh Logic: Every 30 seconds
  useEffect(() => {
    if (!selectedStation) return;

    const interval = setInterval(() => {
      loadStationData(selectedStation, true);
    }, 30000);

    return () => clearInterval(interval);
  }, [selectedStation, loadStationData]);

  const calculateStatus = (location: LocationDetail) => {
    const planned = location.gbttBookedDeparture || location.gbttBookedArrival;
    const actual = location.realtimeDeparture || location.realtimeArrival;

    if (!planned) return { text: "Scheduled", color: "text-blue-400", bg: "bg-blue-400/10" };
    if (!actual || actual === planned) return { text: "On Time", color: "text-emerald-400", bg: "bg-emerald-400/10" }; 

    try {
      const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
      const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
      let diff = aMin - pMin;
      if (diff < -1200) diff += 1440;
      if (diff > 1200) diff -= 1440;

      if (diff <= 0) return { text: "On Time", color: "text-emerald-400", bg: "bg-emerald-400/10" };
      if (diff > 59) return { text: "Delayed", color: "text-rose-400", bg: "bg-rose-400/10" };
      return { text: `${diff}m Late`, color: "text-orange-400", bg: "bg-orange-400/10" };
    } catch (e) {
      return { text: "Live", color: "text-blue-400", bg: "bg-blue-400/10" };
    }
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr || timeStr.length < 4) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  const formatDate = (dateStr?: string) => {
    if (!dateStr) return "N/A";
    // RTT usually returns YYYY-MM-DD or YYYY/MM/DD
    const parts = dateStr.split(/[-/]/);
    if (parts.length === 3) {
      const [year, month, day] = parts;
      return `${day}/${month}/${year}`;
    }
    return dateStr;
  };

  const resetToSearch = () => {
    setSelectedStation(null);
    setDepartures([]);
    setSearchQuery('');
    setSearchError(null);
    setLastUpdated(null);
    setSelectedService(null);
  };

  const closeServiceDetail = () => setSelectedService(null);

  if (!selectedStation) {
    return (
      <div className="min-h-screen text-slate-200 flex flex-col items-center justify-start pt-6 md:pt-12 p-4 sm:p-6 transition-all bg-[#0b1120]">
        <div className="w-full max-w-xl animate-in fade-in slide-in-from-bottom-2 duration-700">
          <header className="mb-4 flex items-center justify-center gap-3">
            <div className="p-1.5 bg-blue-600 rounded-xl text-white shadow-lg">
              <Icons.Train />
            </div>
            <div className="text-left">
              <h1 className="text-xl md:text-2xl font-black tracking-tighter text-white italic uppercase leading-none">UK Rail Live</h1>
              <p className="text-slate-500 text-[8px] font-black uppercase tracking-[0.3em]">Real-time Departures</p>
            </div>
          </header>

          <div className="relative group">
            <div className="relative bg-slate-900 border border-slate-700 rounded-xl p-0.5 shadow-xl">
              <div className="relative flex items-center">
                <div className="absolute left-4 text-slate-500 scale-75">
                  {isSearching ? <div className="animate-spin h-4 w-4 border-2 border-blue-500 border-t-transparent rounded-full" /> : <Icons.Search />}
                </div>
                <input
                  type="text"
                  className="w-full pl-11 pr-4 py-2.5 bg-transparent text-white placeholder-slate-500 focus:outline-none text-base md:text-lg font-bold"
                  placeholder="Enter station name..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  autoFocus
                />
              </div>

              {searchError && (
                <div className="px-4 py-2 text-[10px] font-black text-rose-500 uppercase tracking-widest border-t border-slate-800 bg-rose-500/5">
                   {searchError}
                </div>
              )}

              {searchResults.length > 0 && (
                <div className="mt-0.5 border-t border-slate-800 max-h-64 overflow-y-auto no-scrollbar">
                  {searchResults.map((s) => (
                    <button
                      key={s.crs}
                      onClick={() => loadStationData(s)}
                      className="w-full flex items-center justify-between p-2.5 hover:bg-white/5 text-left transition-colors group"
                    >
                      <div className="flex items-baseline gap-2">
                        <div className="font-bold text-white group-hover:text-blue-400 text-sm md:text-base">{s.name}</div>
                        <div className="text-[9px] text-slate-600 uppercase font-black tracking-widest">{s.crs}</div>
                      </div>
                      <div className="text-slate-800 group-hover:text-blue-500 scale-75">
                        <Icons.ChevronRight />
                      </div>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>

          {!searchResults.length && !searchQuery && (
            <div className="mt-4">
              <div className="flex items-center gap-3 mb-3">
                <div className="h-px bg-slate-800 flex-1"></div>
                <h3 className="text-[8px] font-black text-slate-600 uppercase tracking-[0.4em]">Popular Hubs</h3>
                <div className="h-px bg-slate-800 flex-1"></div>
              </div>
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-1.5">
                {MAJOR_STATIONS.map((s) => (
                  <button
                    key={s.crs}
                    onClick={() => loadStationData(s)}
                    className="px-2 py-1.5 bg-slate-900/40 border border-slate-800/50 hover:border-blue-500/50 hover:bg-slate-800 text-slate-400 hover:text-white rounded-lg text-[9px] font-bold transition-all truncate"
                  >
                    {s.name}
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-slate-100 selection:bg-blue-500/30">
      <nav className="fixed top-0 left-0 right-0 z-50 bg-black/90 backdrop-blur-xl border-b border-white/10 px-4 md:px-8 py-2 md:py-3 flex items-center justify-between">
        <div className="flex items-center gap-4">
          {selectedService && (
             <button 
               onClick={closeServiceDetail}
               className="p-2 hover:bg-white/5 rounded-full text-slate-400 hover:text-white transition-colors"
             >
                <div className="rotate-180 scale-125"><Icons.ChevronRight /></div>
             </button>
          )}
          <div className="flex flex-col">
             <div className="flex items-center gap-2">
                <span className="text-blue-500 font-black tracking-widest text-[9px] uppercase">{selectedStation.crs}</span>
                <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
             </div>
             <h1 className="text-lg md:text-2xl font-black tracking-tighter uppercase italic leading-none truncate max-w-[150px] sm:max-w-none">
               {selectedService ? selectedService.trainIdentity : selectedStation.name}
             </h1>
          </div>
        </div>

        <div className="flex items-center gap-4 md:gap-8">
           <div className="flex flex-col items-end opacity-90">
             <span className="text-[6px] md:text-[8px] font-black text-emerald-500/40 uppercase tracking-[0.3em] mb-0.5">Last Load</span>
             <div className="mono text-emerald-400 text-xs md:text-xl font-bold tracking-[0.15em] drop-shadow-[0_0_8px_rgba(52,211,153,0.6)] bg-emerald-500/5 px-2 py-0.5 rounded border border-emerald-500/10">
               {lastUpdated ? lastUpdated.toLocaleTimeString('en-GB', { hour12: false }) : "--:--:--"}
             </div>
           </div>

           <button 
             onClick={resetToSearch}
             className="flex items-center gap-2 px-3 py-1.5 md:px-5 md:py-2 bg-white text-black hover:bg-slate-200 rounded-full font-black text-[9px] md:text-xs uppercase tracking-widest transition-all shadow-lg active:scale-95 whitespace-nowrap"
           >
             <Icons.Search />
             <span className="hidden sm:inline">Search</span>
           </button>
        </div>
      </nav>

      <main className="pt-16 md:pt-20 pb-4 px-1 sm:px-2 md:px-6 max-w-[1500px] mx-auto animate-in fade-in zoom-in-95 duration-500">
        <div className="rounded-xl md:rounded-2xl bg-[#0c0c0c] border border-white/5 shadow-2xl overflow-hidden relative min-h-[400px]">

          {/* Main Departure Board */}
          {!selectedService && (
            <>
              <div className="hidden md:grid grid-cols-12 gap-4 px-6 py-2 bg-zinc-900/50 border-b border-white/5 text-[8px] font-black uppercase tracking-[0.4em] text-zinc-500">
                <div className="col-span-2">Scheduled</div>
                <div className="col-span-10">Service Details</div>
              </div>

              <div className="divide-y divide-white/5">
                {loading || isServiceLoading ? (
                  <div className="p-32 text-center flex flex-col items-center gap-6">
                    <div className="relative">
                      <div className="h-16 w-16 border-[4px] border-blue-500/10 border-t-blue-500 rounded-full animate-spin" />
                    </div>
                    <div className="text-slate-500 font-black text-[9px] tracking-[0.4em] uppercase animate-pulse">Scanning Platform...</div>
                  </div>
                ) : error ? (
                  <div className="p-16 text-center space-y-6">
                    <div className="text-rose-500 text-4xl">⚠️</div>
                    <div className="space-y-2">
                      <h3 className="text-white font-black text-xl italic uppercase">Connection Error</h3>
                      <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">{error}</p>
                    </div>
                    <button 
                      onClick={() => loadStationData(selectedStation)}
                      className="px-8 py-3 bg-white text-black rounded-xl font-black uppercase tracking-widest text-xs"
                    >
                      Retry
                    </button>
                  </div>
                ) : departures.length === 0 ? (
                  <div className="p-32 text-center">
                    <div className="text-slate-700 font-black text-2xl uppercase italic opacity-20 tracking-tighter mb-2">BOARD CLEAR</div>
                    <div className="text-slate-600 text-[8px] font-black uppercase tracking-[0.2em]">No services found.</div>
                  </div>
                ) : (
                  departures.map((service, idx) => {
                    const status = calculateStatus(service.locationDetail);
                    const destinationName = getFullDestinationName(service);
                    const scheduledTime = service.locationDetail?.gbttBookedDeparture || service.locationDetail?.gbttBookedArrival;
                    const expectedTime = service.locationDetail?.realtimeDeparture || service.locationDetail?.realtimeArrival;

                    return (
                      <button 
                        key={`${service.serviceUid}-${idx}`}
                        onClick={() => handleServiceClick(service)}
                        className="w-full text-left grid grid-cols-12 gap-2 md:gap-4 px-4 md:px-6 py-3 md:py-4 items-start md:items-center hover:bg-white/[0.03] transition-colors group relative border-none appearance-none"
                      >
                        <div className="col-span-3 md:col-span-2 flex flex-col">
                          <div className="text-2xl md:text-4xl font-black mono text-white leading-none tracking-tighter group-hover:text-blue-500 transition-colors">
                            {formatTime(scheduledTime)}
                          </div>
                          {status.text !== "On Time" && expectedTime && (
                            <div className="text-[9px] md:text-[10px] font-black text-blue-400 mono mt-1">
                              EXP {formatTime(expectedTime)}
                            </div>
                          )}
                        </div>

                        <div className="col-span-9 md:col-span-10">
                          <div className="flex flex-wrap items-center gap-x-3 gap-y-1 mb-1">
                            <div className="text-lg md:text-2xl font-black text-slate-100 uppercase tracking-tight leading-tight truncate group-hover:translate-x-1 transition-transform">
                              {destinationName}
                            </div>
                            <div className={`inline-block text-[8px] md:text-[10px] font-black uppercase tracking-[0.1em] px-2 py-0.5 rounded border border-white/5 ${status.bg} ${status.color}`}>
                              {status.text}
                            </div>
                          </div>

                          <div className="flex flex-wrap items-center gap-x-2 gap-y-1">
                             {service.callingPoints ? (
                               <>
                                 <span className="text-[7px] md:text-[8px] font-black text-slate-700 uppercase tracking-widest bg-white/5 px-1.5 py-0.5 rounded">Via:</span>
                                 <div className="flex items-center gap-1.5 overflow-hidden">
                                   {service.callingPoints.map((stop, sIdx) => (
                                     <React.Fragment key={sIdx}>
                                       <span className="text-[9px] md:text-[10px] font-medium text-slate-400 group-hover:text-slate-300 transition-colors cursor-default whitespace-nowrap">
                                         {stop}
                                       </span>
                                       {sIdx < service.callingPoints!.length - 1 && (
                                         <div className="w-0.5 h-0.5 bg-slate-800 rounded-full" />
                                       )}
                                     </React.Fragment>
                                   ))}
                                 </div>
                               </>
                             ) : enriching ? (
                               <div className="flex gap-2 items-center animate-pulse opacity-40">
                                 <div className="h-2 w-8 bg-white/10 rounded" />
                                 <div className="h-2 w-12 bg-white/10 rounded" />
                               </div>
                             ) : (
                               <span className="text-[8px] text-blue-500/20 font-black uppercase tracking-[0.2em] italic">Express Service</span>
                             )}

                             <span className="ml-auto text-[7px] md:text-[8px] text-zinc-700 font-black uppercase tracking-widest hidden md:block">
                              {service.atocName || "National Rail"}
                             </span>
                          </div>
                        </div>
                      </button>
                    );
                  })
                )}
              </div>
            </>
          )}

          {/* Service Journey Detail View */}
          {selectedService && (
            <div className="p-4 md:p-6 animate-in fade-in slide-in-from-right-4 duration-500">
              <header className="mb-4 flex flex-row items-center justify-between gap-4 border-b border-white/5 pb-3">
                <div className="flex items-center gap-4">
                  <div className="flex flex-col">
                    <div className="flex items-center gap-2 mb-0.5">
                      <span className="text-[8px] font-black text-blue-500 uppercase tracking-[0.3em]">{selectedService.trainIdentity}</span>
                      <span className="px-1.5 py-0.5 bg-zinc-800 rounded text-[7px] font-black text-zinc-400 uppercase tracking-widest">{selectedService.atocName}</span>
                    </div>
                    <h2 className="text-xl md:text-3xl font-black italic uppercase tracking-tighter text-white leading-none">
                      Journey Timeline
                    </h2>
                  </div>
                </div>
                <div className="text-right flex flex-col items-end">
                  <span className="text-[7px] font-black text-slate-600 uppercase tracking-[0.3em]">Operational Date</span>
                  <div className="text-sm font-bold text-slate-400 uppercase leading-none mt-1">{formatDate(selectedService.runDate)}</div>
                </div>
              </header>

              <div className="max-w-4xl mx-auto space-y-0 relative">
                {/* Timeline vertical bar */}
                <div className="absolute left-[2.4rem] md:left-[3.4rem] top-6 bottom-6 w-0.5 bg-zinc-900 z-0" />

                {selectedService.locations.map((loc, lIdx) => {
                  const status = calculateStatus(loc);
                  const isOrigin = lIdx === 0;
                  const isDestination = lIdx === selectedService.locations.length - 1;
                  const isCurrent = loc.crs === selectedStation.crs;
                  const time = loc.gbttBookedArrival || loc.gbttBookedDeparture;
                  const actual = loc.realtimeArrival || loc.realtimeDeparture;

                  return (
                    <div 
                      key={`${loc.crs}-${lIdx}`} 
                      className={`relative flex items-center gap-4 md:gap-8 py-2 md:py-3 px-2 rounded-lg transition-all ${isCurrent ? 'bg-blue-600/5 border border-blue-500/10' : 'hover:bg-white/[0.01]'}`}
                    >
                      {/* Timeline Dot */}
                      <div className="flex flex-col items-center z-10 w-14 md:w-20">
                         <div className={`mono text-[9px] md:text-xs font-bold ${isCurrent ? 'text-blue-400' : 'text-slate-500'}`}>
                           {formatTime(time)}
                         </div>
                         <div className={`mt-1 h-3 w-3 rounded-full border-2 bg-black transition-all ${isCurrent ? 'border-blue-500 scale-110 shadow-[0_0_8px_rgba(59,130,246,0.4)]' : 'border-zinc-800'}`} />
                      </div>

                      {/* Content */}
                      <div className="flex-1 flex flex-col md:flex-row md:items-center justify-between gap-1">
                        <div>
                          <div className="flex items-center gap-2">
                            <span className={`text-sm md:text-lg font-black uppercase tracking-tight leading-tight ${isCurrent ? 'text-blue-400' : 'text-slate-200'}`}>
                              {loc.description}
                            </span>
                            <span className="text-[7px] font-black text-slate-700 tracking-widest uppercase">{loc.crs}</span>
                          </div>
                          <div className="flex items-center gap-3 mt-0.5">
                            {loc.platform && (
                              <span className="px-1 py-0.5 bg-zinc-900 border border-zinc-800 rounded text-[8px] font-black text-zinc-500 uppercase tracking-widest">
                                P{loc.platform}
                              </span>
                            )}
                            <span className={`text-[8px] md:text-[9px] font-black uppercase tracking-widest ${status.color}`}>
                              {status.text === "On Time" ? (actual ? 'Arrived On Time' : 'On Time') : status.text}
                            </span>
                          </div>
                        </div>

                        <div className="flex items-center gap-3">
                           {actual && actual !== time && (
                             <div className="flex flex-col items-end">
                               <span className="text-[6px] font-black text-slate-700 uppercase tracking-widest">Realtime</span>
                               <span className="mono text-blue-400 font-bold text-[10px] md:text-xs">{formatTime(actual)}</span>
                             </div>
                           )}
                           {isOrigin && <span className="text-[7px] font-black bg-emerald-500/5 text-emerald-500/80 px-1.5 py-0.5 rounded border border-emerald-500/10 uppercase tracking-widest">Origin</span>}
                           {isDestination && <span className="text-[7px] font-black bg-rose-500/5 text-rose-500/80 px-1.5 py-0.5 rounded border border-rose-500/10 uppercase tracking-widest">Dest</span>}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>

              <div className="mt-8 flex justify-center">
                 <button 
                   onClick={closeServiceDetail}
                   className="px-6 py-2 bg-zinc-900 border border-zinc-800 hover:bg-white hover:text-black transition-all rounded-full font-black uppercase tracking-[0.3em] text-[9px] shadow-lg"
                 >
                   Return to Board
                 </button>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="px-6 py-4 flex flex-col md:flex-row justify-between items-center gap-2 border-t border-white/5 opacity-40">
         <div className="flex items-center gap-6 text-[8px] font-black uppercase tracking-[0.2em] text-zinc-600">
            <span className="flex items-center gap-1.5"><span className="w-1.5 h-1.5 rounded-full bg-blue-600" /> LIVE DATA</span>
            <span>GEMINI ENGINE</span>
            <span className="flex items-center gap-1.5 animate-pulse"><span className="w-1 h-1 rounded-full bg-emerald-500" /> AUTO-REFRESHING (30s)</span>
         </div>
         <div className="text-[8px] font-black uppercase tracking-[0.2em] text-zinc-800">
           {selectedService ? 'DETAILED VIEW' : 'BOARD ACTIVE'}
         </div>
      </footer>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }

        @media (orientation: landscape) and (max-height: 600px) {
           nav { padding-top: 0.25rem; padding-bottom: 0.25rem; }
           .pt-16 { padding-top: 3rem; }
           .py-3 { padding-top: 0.5rem; padding-bottom: 0.5rem; }
           .text-2xl { font-size: 1.15rem; }
           .text-lg { font-size: 0.95rem; }
        }

        @media (min-height: 700px) {
           .py-4 { padding-top: 1rem; padding-bottom: 1rem; }
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse, ServiceDetail, LocationDetail } from './types';
import { fetchDepartures, fetchServiceDetails } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<ServiceDetail | null>(null);
  const [isServiceLoading, setIsServiceLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);

  const latestQueryRef = useRef('');

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      setSearchError(null);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      setSearchError(null);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
          if (!results || results.length === 0) {
             setSearchError("No stations found");
          }
        }
      } catch (err) {
        console.error("Search error:", err);
        if (latestQueryRef.current === searchQuery) {
          setSearchError("Lookup service unavailable");
        }
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const getStationName = (obj: any): string => {
    if (!obj) return "";
    if (Array.isArray(obj)) {
      if (obj.length === 0) return "";
      return getStationName(obj[obj.length - 1]);
    }
    return obj.description || obj.locationName || obj.publicName || obj.name || obj.crs || "";
  };

  const getFullDestinationName = (service: Service): string => {
    let name = getStationName(service.destination);
    if (!name && service.locationDetail) {
      name = getStationName(service.locationDetail.destination);
    }
    return name || "Check Board";
  };

  const loadStationData = useCallback(async (station: Station, silent: boolean = false) => {
    if (!station || !station.crs) return;

    if (!silent) {
      setLoading(true);
      setDepartures([]);
      setSelectedService(null);
    }

    setEnriching(false);
    setError(null);
    setSelectedStation(station);
    setSearchQuery('');

    try {
      const data = await fetchDepartures(station.crs);
      const services = Array.isArray(data.services) ? data.services : [];

      setDepartures(services);
      setLastUpdated(new Date());

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 15).map(s => ({
          origin: getStationName(s.origin) || "Origin",
          destination: getFullDestinationName(s),
          via: station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults || enrichedResults.length === 0) return;

          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || 
              destName.includes(r.destination.toLowerCase())
            );

            if (match && match.stops.length > 0) {
              return { ...s, callingPoints: match.stops };
            }
            return s;
          }));
        }).catch(err => {
          console.warn("Failed to fetch calling points:", err);
        }).finally(() => {
          setEnriching(false);
        });
      }

    } catch (err: any) {
      console.error(err);
      if (!silent) {
        setError(err.message || "An unexpected error occurred.");
      }
    } finally {
      if (!silent) {
        setLoading(false);
      }
    }
  }, []);

  const handleServiceClick = async (service: Service) => {
    setIsServiceLoading(true);
    try {
      const details = await fetchServiceDetails(service.serviceUid, service.runDate);
      setSelectedService(details);
    } catch (err: any) {
      alert("Failed to load service details: " + err.message);
    } finally {
      setIsServiceLoading(false);
    }
  };

  // Automatic Refresh Logic: Every 30 seconds
  useEffect(() => {
    if (!selectedStation) return;

    const interval = setInterval(() => {
      loadStationData(selectedStation, true);
    }, 30000);

    return () => clearInterval(interval);
  }, [selectedStation, loadStationData]);

  const calculateStatus = (location: LocationDetail) => {
    const planned = location.gbttBookedDeparture || location.gbttBookedArrival;
    const actual = location.realtimeDeparture || location.realtimeArrival;

    if (!planned) return { text: "Scheduled", color: "text-blue-400", bg: "bg-blue-400/10" };
    if (!actual || actual === planned) return { text: "On Time", color: "text-emerald-400", bg: "bg-emerald-400/10" }; 

    try {
      const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
      const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
      let diff = aMin - pMin;
      if (diff < -1200) diff += 1440;
      if (diff > 1200) diff -= 1440;

      if (diff <= 0) return { text: "On Time", color: "text-emerald-400", bg: "bg-emerald-400/10" };
      if (diff > 59) return { text: "Delayed", color: "text-rose-400", bg: "bg-rose-400/10" };
      return { text: `${diff}m Late`, color: "text-orange-400", bg: "bg-orange-400/10" };
    } catch (e) {
      return { text: "Live", color: "text-blue-400", bg: "bg-blue-400/10" };
    }
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr || timeStr.length < 4) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  const formatDate = (dateStr?: string) => {
    if (!dateStr) return "N/A";
    const parts = dateStr.split(/[-/]/);
    if (parts.length === 3) {
      const [year, month, day] = parts;
      return `${day}/${month}/${year}`;
    }
    return dateStr;
  };

  const resetToSearch = () => {
    setSelectedStation(null);
    setDepartures([]);
    setSearchQuery('');
    setSearchError(null);
    setLastUpdated(null);
    setSelectedService(null);
  };

  const closeServiceDetail = () => setSelectedService(null);

  if (!selectedStation) {
    return (
      <div className="min-h-screen text-slate-200 flex flex-col items-center justify-start pt-6 md:pt-12 p-4 sm:p-6 transition-all bg-[#0b1120]">
        <div className="w-full max-w-xl animate-in fade-in slide-in-from-bottom-2 duration-700">
          <header className="mb-4 flex items-center justify-center gap-3">
            <div className="p-1.5 bg-blue-600 rounded-xl text-white shadow-lg">
              <Icons.Train />
            </div>
            <div className="text-left">
              <h1 className="text-xl md:text-2xl font-black tracking-tighter text-white italic uppercase leading-none">UK Rail Live</h1>
              <p className="text-slate-500 text-[8px] font-black uppercase tracking-[0.3em]">Real-time Departures</p>
            </div>
          </header>

          <div className="relative group">
            <div className="relative bg-slate-900 border border-slate-700 rounded-xl p-0.5 shadow-xl">
              <div className="relative flex items-center">
                <div className="absolute left-4 text-slate-500 scale-75">
                  {isSearching ? <div className="animate-spin h-4 w-4 border-2 border-blue-500 border-t-transparent rounded-full" /> : <Icons.Search />}
                </div>
                <input
                  type="text"
                  className="w-full pl-11 pr-4 py-2.5 bg-transparent text-white placeholder-slate-500 focus:outline-none text-base md:text-lg font-bold"
                  placeholder="Enter station name..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  autoFocus
                />
              </div>

              {searchError && (
                <div className="px-4 py-2 text-[10px] font-black text-rose-500 uppercase tracking-widest border-t border-slate-800 bg-rose-500/5">
                   {searchError}
                </div>
              )}

              {searchResults.length > 0 && (
                <div className="mt-0.5 border-t border-slate-800 max-h-64 overflow-y-auto no-scrollbar">
                  {searchResults.map((s) => (
                    <button
                      key={s.crs}
                      onClick={() => loadStationData(s)}
                      className="w-full flex items-center justify-between p-2.5 hover:bg-white/5 text-left transition-colors group"
                    >
                      <div className="flex items-baseline gap-2">
                        <div className="font-bold text-white group-hover:text-blue-400 text-sm md:text-base">{s.name}</div>
                        <div className="text-[9px] text-slate-600 uppercase font-black tracking-widest">{s.crs}</div>
                      </div>
                      <div className="text-slate-800 group-hover:text-blue-500 scale-75">
                        <Icons.ChevronRight />
                      </div>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>

          {!searchResults.length && !searchQuery && (
            <div className="mt-4">
              <div className="flex items-center gap-3 mb-3">
                <div className="h-px bg-slate-800 flex-1"></div>
                <h3 className="text-[8px] font-black text-slate-600 uppercase tracking-[0.4em]">Popular Hubs</h3>
                <div className="h-px bg-slate-800 flex-1"></div>
              </div>
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-1.5">
                {MAJOR_STATIONS.map((s) => (
                  <button
                    key={s.crs}
                    onClick={() => loadStationData(s)}
                    className="px-2 py-1.5 bg-slate-900/40 border border-slate-800/50 hover:border-blue-500/50 hover:bg-slate-800 text-slate-400 hover:text-white rounded-lg text-[9px] font-bold transition-all truncate"
                  >
                    {s.name}
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-slate-100 selection:bg-blue-500/30">
      <nav className="fixed top-0 left-0 right-0 z-50 bg-black/90 backdrop-blur-xl border-b border-white/10 px-4 md:px-8 py-2 md:py-3 flex items-center justify-between">
        <div className="flex items-center gap-4">
          {selectedService && (
             <button 
               onClick={closeServiceDetail}
               className="p-2 hover:bg-white/5 rounded-full text-slate-400 hover:text-white transition-colors"
             >
                <div className="rotate-180 scale-125"><Icons.ChevronRight /></div>
             </button>
          )}
          <div className="flex flex-col">
             <div className="flex items-center gap-2">
                <span className="text-blue-500 font-black tracking-widest text-[9px] uppercase">{selectedStation.crs}</span>
                <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
             </div>
             <h1 className="text-lg md:text-2xl font-black tracking-tighter uppercase italic leading-none truncate max-w-[150px] sm:max-w-none">
               {selectedService ? selectedService.trainIdentity : selectedStation.name}
             </h1>
          </div>
        </div>

        <div className="flex items-center gap-4 md:gap-8">
           <div className="flex flex-col items-end opacity-90">
             <span className="text-[6px] md:text-[8px] font-black text-emerald-500/40 uppercase tracking-[0.3em] mb-0.5">Last Load</span>
             <div className="mono text-emerald-400 text-xs md:text-xl font-bold tracking-[0.15em] drop-shadow-[0_0_8px_rgba(52,211,153,0.6)] bg-emerald-500/5 px-2 py-0.5 rounded border border-emerald-500/10">
               {lastUpdated ? lastUpdated.toLocaleTimeString('en-GB', { hour12: false }) : "--:--:--"}
             </div>
           </div>

           <button 
             onClick={resetToSearch}
             className="flex items-center gap-2 px-3 py-1.5 md:px-5 md:py-2 bg-white text-black hover:bg-slate-200 rounded-full font-black text-[9px] md:text-xs uppercase tracking-widest transition-all shadow-lg active:scale-95 whitespace-nowrap"
           >
             <Icons.Search />
             <span className="hidden sm:inline">Search</span>
           </button>
        </div>
      </nav>

      <main className="pt-16 md:pt-20 pb-4 px-1 sm:px-2 md:px-6 max-w-[1500px] mx-auto animate-in fade-in zoom-in-95 duration-500">
        <div className="rounded-xl md:rounded-2xl bg-[#0c0c0c] border border-white/5 shadow-2xl overflow-hidden relative min-h-[400px]">

          {/* Main Departure Board */}
          {!selectedService && (
            <>
              <div className="hidden md:grid grid-cols-12 gap-4 px-6 py-2 bg-zinc-900/50 border-b border-white/5 text-[8px] font-black uppercase tracking-[0.4em] text-zinc-500">
                <div className="col-span-2">Scheduled</div>
                <div className="col-span-10">Service Details</div>
              </div>

              <div className="divide-y divide-white/5">
                {loading || isServiceLoading ? (
                  <div className="p-32 text-center flex flex-col items-center gap-6">
                    <div className="relative">
                      <div className="h-16 w-16 border-[4px] border-blue-500/10 border-t-blue-500 rounded-full animate-spin" />
                    </div>
                    <div className="text-slate-500 font-black text-[9px] tracking-[0.4em] uppercase animate-pulse">Scanning Platform...</div>
                  </div>
                ) : error ? (
                  <div className="p-16 text-center space-y-6">
                    <div className="text-rose-500 text-4xl">⚠️</div>
                    <div className="space-y-2">
                      <h3 className="text-white font-black text-xl italic uppercase">Connection Error</h3>
                      <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">{error}</p>
                    </div>
                    <button 
                      onClick={() => loadStationData(selectedStation)}
                      className="px-8 py-3 bg-white text-black rounded-xl font-black uppercase tracking-widest text-xs"
                    >
                      Retry
                    </button>
                  </div>
                ) : departures.length === 0 ? (
                  <div className="p-32 text-center">
                    <div className="text-slate-700 font-black text-2xl uppercase italic opacity-20 tracking-tighter mb-2">BOARD CLEAR</div>
                    <div className="text-slate-600 text-[8px] font-black uppercase tracking-[0.2em]">No services found.</div>
                  </div>
                ) : (
                  departures.map((service, idx) => {
                    const status = calculateStatus(service.locationDetail);
                    const destinationName = getFullDestinationName(service);
                    const scheduledTime = service.locationDetail?.gbttBookedDeparture || service.locationDetail?.gbttBookedArrival;
                    const expectedTime = service.locationDetail?.realtimeDeparture || service.locationDetail?.realtimeArrival;

                    return (
                      <button 
                        key={`${service.serviceUid}-${idx}`}
                        onClick={() => handleServiceClick(service)}
                        className="w-full text-left grid grid-cols-12 gap-2 md:gap-4 px-4 md:px-6 py-3 md:py-4 items-start md:items-center hover:bg-white/[0.03] transition-colors group relative border-none appearance-none"
                      >
                        <div className="col-span-3 md:col-span-2 flex flex-col">
                          <div className="text-2xl md:text-4xl font-black mono text-white leading-none tracking-tighter group-hover:text-blue-500 transition-colors">
                            {formatTime(scheduledTime)}
                          </div>
                          {status.text !== "On Time" && expectedTime && (
                            <div className="text-[9px] md:text-[10px] font-black text-blue-400 mono mt-1">
                              EXP {formatTime(expectedTime)}
                            </div>
                          )}
                        </div>

                        <div className="col-span-9 md:col-span-10">
                          <div className="flex flex-wrap items-center gap-x-3 gap-y-1 mb-1">
                            <div className="text-lg md:text-2xl font-black text-slate-100 uppercase tracking-tight leading-tight truncate group-hover:translate-x-1 transition-transform">
                              {destinationName}
                            </div>
                            <div className={`inline-block text-[8px] md:text-[10px] font-black uppercase tracking-[0.1em] px-2 py-0.5 rounded border border-white/5 ${status.bg} ${status.color}`}>
                              {status.text}
                            </div>
                          </div>

                          <div className="flex flex-wrap items-center gap-x-2 gap-y-1">
                             {service.callingPoints ? (
                               <>
                                 <span className="text-[7px] md:text-[8px] font-black text-slate-700 uppercase tracking-widest bg-white/5 px-1.5 py-0.5 rounded">Via:</span>
                                 <div className="flex items-center gap-1.5 overflow-hidden">
                                   {service.callingPoints.map((stop, sIdx) => (
                                     <React.Fragment key={sIdx}>
                                       <span className="text-[9px] md:text-[10px] font-medium text-slate-400 group-hover:text-slate-300 transition-colors cursor-default whitespace-nowrap">
                                         {stop}
                                       </span>
                                       {sIdx < service.callingPoints!.length - 1 && (
                                         <div className="w-0.5 h-0.5 bg-slate-800 rounded-full" />
                                       )}
                                     </React.Fragment>
                                   ))}
                                 </div>
                               </>
                             ) : enriching ? (
                               <div className="flex gap-2 items-center animate-pulse opacity-40">
                                 <div className="h-2 w-8 bg-white/10 rounded" />
                                 <div className="h-2 w-12 bg-white/10 rounded" />
                               </div>
                             ) : (
                               <span className="text-[8px] text-blue-500/20 font-black uppercase tracking-[0.2em] italic">Express Service</span>
                             )}

                             <span className="ml-auto text-[7px] md:text-[8px] text-zinc-700 font-black uppercase tracking-widest hidden md:block">
                              {service.atocName || "National Rail"}
                             </span>
                          </div>
                        </div>
                      </button>
                    );
                  })
                )}
              </div>
            </>
          )}

          {/* Service Journey Detail View */}
          {selectedService && (
            <div className="p-4 md:p-6 animate-in fade-in slide-in-from-right-4 duration-500">
              <header className="mb-4 flex flex-row items-center justify-between gap-4 border-b border-white/5 pb-3">
                <div className="flex items-center gap-4">
                  <div className="flex flex-col">
                    <div className="flex items-center gap-2 mb-0.5">
                      <span className="text-[8px] font-black text-blue-500 uppercase tracking-[0.3em]">{selectedService.trainIdentity}</span>
                      <span className="px-1.5 py-0.5 bg-zinc-800 rounded text-[7px] font-black text-zinc-400 uppercase tracking-widest">{selectedService.atocName}</span>
                    </div>
                    <h2 className="text-xl md:text-3xl font-black italic uppercase tracking-tighter text-white leading-none">
                      Journey Timeline
                    </h2>
                  </div>
                </div>
                <div className="text-right flex flex-col items-end">
                  <span className="text-[7px] font-black text-slate-600 uppercase tracking-[0.3em]">Operational Date</span>
                  <div className="text-sm font-bold text-slate-400 uppercase leading-none mt-1">{formatDate(selectedService.runDate)}</div>
                </div>
              </header>

              <div className="max-w-4xl mx-auto space-y-0 relative">
                {/* Timeline vertical bar */}
                <div className="absolute left-[2.4rem] md:left-[3.4rem] top-6 bottom-6 w-0.5 bg-zinc-900 z-0" />

                {selectedService.locations.map((loc, lIdx) => {
                  const status = calculateStatus(loc);
                  const isOrigin = lIdx === 0;
                  const isDestination = lIdx === selectedService.locations.length - 1;
                  const isCurrent = loc.crs === selectedStation.crs;
                  const time = loc.gbttBookedArrival || loc.gbttBookedDeparture;
                  const actual = loc.realtimeArrival || loc.realtimeDeparture;

                  // Custom status label based on actual arrival/departure
                  const getDetailStatusText = () => {
                    const baseStatus = status.text; // "On Time", "5m Late", etc.

                    if (isDestination) {
                      if (loc.realtimeArrivalActual) return `Arrived ${baseStatus}`;
                      return baseStatus;
                    }

                    if (loc.realtimeDepartureActual) {
                      return `Departed ${baseStatus}`;
                    }

                    if (loc.realtimeArrivalActual) {
                      return `Arrived ${baseStatus}`;
                    }

                    return baseStatus;
                  };

                  return (
                    <div 
                      key={`${loc.crs}-${lIdx}`} 
                      className={`relative flex items-center gap-4 md:gap-8 py-2 md:py-3 px-2 rounded-lg transition-all ${isCurrent ? 'bg-blue-600/5 border border-blue-500/10' : 'hover:bg-white/[0.01]'}`}
                    >
                      {/* Timeline Dot */}
                      <div className="flex flex-col items-center z-10 w-14 md:w-20">
                         <div className={`mono text-[9px] md:text-xs font-bold ${isCurrent ? 'text-blue-400' : 'text-slate-500'}`}>
                           {formatTime(time)}
                         </div>
                         <div className={`mt-1 h-3 w-3 rounded-full border-2 bg-black transition-all ${isCurrent ? 'border-blue-500 scale-110 shadow-[0_0_8px_rgba(59,130,246,0.4)]' : 'border-zinc-800'}`} />
                      </div>

                      {/* Content */}
                      <div className="flex-1 flex flex-col md:flex-row md:items-center justify-between gap-1">
                        <div>
                          <div className="flex items-center gap-2">
                            <span className={`text-sm md:text-lg font-black uppercase tracking-tight leading-tight ${isCurrent ? 'text-blue-400' : 'text-slate-200'}`}>
                              {loc.description}
                            </span>
                            <span className="text-[7px] font-black text-slate-700 tracking-widest uppercase">{loc.crs}</span>
                          </div>
                          <div className="flex items-center gap-3 mt-0.5">
                            {loc.platform && (
                              <span className="px-1 py-0.5 bg-zinc-900 border border-zinc-800 rounded text-[8px] font-black text-zinc-500 uppercase tracking-widest">
                                P{loc.platform}
                              </span>
                            )}
                            <span className={`text-[8px] md:text-[9px] font-black uppercase tracking-widest ${status.color}`}>
                              {getDetailStatusText()}
                            </span>
                          </div>
                        </div>

                        <div className="flex items-center gap-3">
                           {actual && actual !== time && (
                             <div className="flex flex-col items-end">
                               <span className="text-[6px] font-black text-slate-700 uppercase tracking-widest">Realtime</span>
                               <span className="mono text-blue-400 font-bold text-[10px] md:text-xs">{formatTime(actual)}</span>
                             </div>
                           )}
                           {isOrigin && <span className="text-[7px] font-black bg-emerald-500/5 text-emerald-500/80 px-1.5 py-0.5 rounded border border-emerald-500/10 uppercase tracking-widest">Origin</span>}
                           {isDestination && <span className="text-[7px] font-black bg-rose-500/5 text-rose-500/80 px-1.5 py-0.5 rounded border border-rose-500/10 uppercase tracking-widest">Dest</span>}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>

              <div className="mt-8 flex justify-center">
                 <button 
                   onClick={closeServiceDetail}
                   className="px-6 py-2 bg-zinc-900 border border-zinc-800 hover:bg-white hover:text-black transition-all rounded-full font-black uppercase tracking-[0.3em] text-[9px] shadow-lg"
                 >
                   Return to Board
                 </button>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="px-6 py-4 flex flex-col md:flex-row justify-between items-center gap-2 border-t border-white/5 opacity-40">
         <div className="flex items-center gap-6 text-[8px] font-black uppercase tracking-[0.2em] text-zinc-600">
            <span className="flex items-center gap-1.5"><span className="w-1.5 h-1.5 rounded-full bg-blue-600" /> LIVE DATA</span>
            <span>GEMINI ENGINE</span>
            <span className="flex items-center gap-1.5 animate-pulse"><span className="w-1 h-1 rounded-full bg-emerald-500" /> AUTO-REFRESHING (30s)</span>
         </div>
         <div className="text-[8px] font-black uppercase tracking-[0.2em] text-zinc-800">
           {selectedService ? 'DETAILED VIEW' : 'BOARD ACTIVE'}
         </div>
      </footer>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }

        @media (orientation: landscape) and (max-height: 600px) {
           nav { padding-top: 0.25rem; padding-bottom: 0.25rem; }
           .pt-16 { padding-top: 3rem; }
           .py-3 { padding-top: 0.5rem; padding-bottom: 0.5rem; }
           .text-2xl { font-size: 1.15rem; }
           .text-lg { font-size: 0.95rem; }
        }

        @media (min-height: 700px) {
           .py-4 { padding-top: 1rem; padding-bottom: 1rem; }
        }
      `}</style>
    </div>
  );
};

export default App;
